async #handleRequest(req: http.IncomingMessage, res: http.ServerResponse): Promise<void> {
        if (req.method === "GET" && req.url?.startsWith("/webhook")) {
            this.#handleVerification(req, res);
        } else if (req.method === "POST" && req.url === "/webhook") {
            await this.#handleIncomingEvent(req, res);
        } else {
            res.writeHead(404);
            res.end("Not Found");
        }
    }

#handleVerification(req: http.IncomingMessage, res: http.ServerResponse): void {
        const url = new URL(req.url!, `http://${req.headers.host}`);
        const mode = url.searchParams.get("hub.mode");
        const token = url.searchParams.get("hub.verify_token");
        const challenge = url.searchParams.get("hub.challenge");

        if (mode === "subscribe" && token === this.#verifyToken) {
            logger.info("[MetaBridge] Webhook Verified Successfully!");
            res.writeHead(200);
            res.end(challenge);
        } else {
            logger.warn("[MetaBridge] Webhook Verification Failed!");
            res.writeHead(403);
            res.end("Forbidden");
        }
    }

async #handleIncomingEvent(req: http.IncomingMessage, res: http.ServerResponse): Promise<void> {
        let rawBody = "";
        req.on("data", chunk => { rawBody += chunk.toString(); });
        req.on("end", () => {
            // 1. Verify Signature (Zero-Trust Guard)
            const signature = req.headers["x-hub-signature-256"] as string;
            if (!this.#verifySignature(rawBody, signature)) {
                logger.warn("[MetaBridge] 🛡️ Invalid X-Hub-Signature-256. Dropping payload.");
                res.writeHead(401);
                return res.end("Unauthorized");
            }

            // 2. Parse and Process
            try {
                const body = JSON.parse(rawBody);

                if (body.object === "page" || body.object === "instagram") {
                    body.entry.forEach((entry: any) => {
                        const webhookEvent = entry.messaging[0];
                        const senderId = webhookEvent.sender.id;

                        // Normal Message
                        if (webhookEvent.message && webhookEvent.message.text) {
                            const normalizedMsg: NormalizedMessage = {
                                rawPayload: webhookEvent,
                                channel: this.channelName,
                                senderId: senderId,
                                senderName: "Meta User", // Need extra API call to get real name, defer to UI layer
                                text: webhookEvent.message.text,
                                timestamp: webhookEvent.timestamp
                            };
                            this.emit("message", normalizedMsg);
                        } 
                        // Postback (Button Click)
                        else if (webhookEvent.postback) {
                            if (webhookEvent.postback.payload) {
                                this.emit("postback", {
                                    senderId: senderId,
                                    payload: webhookEvent.postback.payload
                                });
                            }
                        }
                    });

                    // Meta requires a fast 200 OK
                    res.writeHead(200);
                    res.end("EVENT_RECEIVED");
                } else {
                    res.writeHead(404);
                    res.end();
                }
            } catch (e: unknown) {
            const errMsg = e instanceof Error ? e.message : String(e);
                logger.error(`[MetaBridge] Payload processing error: ${errMsg}`);
                res.writeHead(500);
                res.end("Internal Error");
            }
        });
    }

#verifySignature(rawBody: string, signatureHeader?: string): boolean {
        /* istanbul ignore if */
        if (!signatureHeader || !signatureHeader.startsWith("sha256=")) return false;
        const expectedHash = crypto
            .createHmac("sha256", this.#appSecret)
            .update(rawBody)
            .digest("hex");
        
        const expectedSignature = `sha256=${expectedHash}`;
        
        try {
            return crypto.timingSafeEqual(
                Buffer.from(expectedSignature),
                Buffer.from(signatureHeader)
            );
        } catch {
            return false;
        }
    }

class TelegramBridge extends EventEmitter implements ChannelAdapter {
    public readonly channelName = "telegram" as const;

    readonly #botToken: string;
    readonly #allowedIds: Set<string>;
    #bot: Telegraf | null = null;
    #commandHandler: TelegramCommandHandler;
    #cdpBridge: CDPBridge | null = null;
    #isPolling = false;
    #reconnectTimer: ReturnType<typeof setTimeout> | null = null;

    constructor() {
        super();
        this.#botToken = process.env.TELEGRAM_BOT_TOKEN || "";
        const allowedRaw = process.env.TELEGRAM_ALLOWED_IDS || "";
        this.#allowedIds = new Set(
            allowedRaw.split(",").map(id => id.trim()).filter(Boolean)
        );

        this.#commandHandler = new TelegramCommandHandler();

        if (!this.#botToken) {
            logger.warn("⚠️ [Telegram] TELEGRAM_BOT_TOKEN chưa cấu hình. Bridge tạm tắt.");
        } else {
            this.#bot = new Telegraf(this.#botToken, { handlerTimeout: 900_000 });
            this.#setupBot();
            logger.info(`📡 [Telegram] Bridge khởi tạo (Telegraf). Whitelist: ${this.#allowedIds.size} IDs.`);
        }
    }

    public setBridges(
        cdpBridge: CDPBridge, 
        autoAcceptDaemon?: any, 
        agentLoop?: any, 
        sessions?: any, 
        memory?: any
    ): void {
        this.#cdpBridge = cdpBridge;
        if (this.#bot) {
            this.#commandHandler.registerHandlers(
                this.#bot, 
                this.#cdpBridge, 
                autoAcceptDaemon, 
                this, 
                agentLoop, 
                sessions, 
                memory
            );
        }
    }

    #setupBot(): void {
        if (!this.#bot) return;
        // 1. Auth Middleware (ZMAS Guard)
        this.#bot.use((ctx, next) => {
            const senderId = String(ctx.from?.id);
            if (this.#allowedIds.size > 0 && !this.#allowedIds.has(senderId)) {
                logger.warn(`[Telegram] 🛡️ Blocked unauthorized sender: ${senderId}`);
                return; // drop silently or ctx.reply("⛔ Unauthorized")
            }
            return next();
        });

        // 2. Handle standard text messages (pass to AgentLoop)
        this.#bot.on("text", (ctx, next) => {
            // If it's a command, let command handlers handle it
            if (ctx.message.text.startsWith("/")) {
                return next();
            }

            const normalized: NormalizedMessage = {
                channel: "telegram",
                senderId: String(ctx.from.id),
                senderName: ctx.from.first_name,
                text: ctx.message.text,
                rawPayload: ctx.update,
                timestamp: ctx.message.date * 1000,
            };
            
            logger.info(`💬 [Telegram] Tin nhắn từ ${normalized.senderName}: "${normalized.text}"`);
            this.emit("message", normalized);
        });

        // 3. Handle photos
        this.#bot.on("photo", (ctx) => {
            const normalized: NormalizedMessage = {
                channel: "telegram",
                senderId: String(ctx.from.id),
                senderName: ctx.from.first_name,
                text: ctx.message.caption || "",
                rawPayload: ctx.update,
                timestamp: ctx.message.date * 1000,
            };
            const largest = ctx.message.photo[ctx.message.photo.length - 1];
            normalized.mediaUrl = largest.file_id;
            normalized.mediaType = "image";
            
            logger.info(`💬 [Telegram] Hình ảnh từ ${normalized.senderName}`);
            this.emit("message", normalized);
        });

        // 4. Handle Callback Queries (Approve/Reject buttons)
        this.#bot.on("callback_query", async (ctx) => {
            // @ts-expect-error - telegraf types for callback query data
            const data = ctx.callbackQuery.data;
            if (!data) return;

            logger.info(`🔘 [Telegram] Callback query: ${data} from ${ctx.from.first_name}`);
            this.emit("callback_query", {
                queryId: ctx.callbackQuery.id,
                senderId: String(ctx.from.id),
                data: data,
                chatId: ctx.chat?.id,
                messageId: ctx.callbackQuery.message?.message_id,
            });

            try {
                await ctx.answerCbQuery();
            } catch (e) {
                // ignore
            }
        });
    }

    #hasLogged409 = false;

    public async startPolling(): Promise<void> {
        if (!this.#bot || this.#isPolling) return;
        try {
            await this.#bot.launch({ dropPendingUpdates: true });
            this.#isPolling = true;
            this.#hasLogged409 = false;
            logger.info("📡 [Telegram] Bắt đầu Long-Polling (Telegraf)...");
        } catch (e: unknown) {
            const errMsg = e instanceof Error ? e.message : String(e);
            const isConflict = errMsg.includes("409");
            
            if (isConflict) {
                if (!this.#hasLogged409) {
                    logger.warn(`[Telegram] Bị chiếm quyền Bot Token bởi 1 tiến trình khác (409 Conflict). Tự động thử lại ngầm (30s)...`);
                    this.#hasLogged409 = true;
                }
            } else {
                logger.error(`[Telegram] Polling error: ${errMsg}. Auto-reconnect in 10s...`);
            }
            
            // Guard: clear any existing timer before scheduling a new one
            if (this.#reconnectTimer) clearTimeout(this.#reconnectTimer);
            this.#reconnectTimer = setTimeout(() => this.startPolling(), isConflict ? 30_000 : 10_000);
        }
    }

    public stop(): void {
        if (this.#reconnectTimer) {
            clearTimeout(this.#reconnectTimer);
            this.#reconnectTimer = null;
        }
        if (!this.#isPolling || !this.#bot) return;
        this.#isPolling = false;
        this.#bot.stop("SIGTERM");
        logger.info("⚠️ [Telegram] Bridge đã dừng.");
    }

    // ═══════════════════════════════════════
    //  Outbound API Methods (ChannelAdapter)
    // ═══════════════════════════════════════

    public async sendText(chatId: string, text: string): Promise<void> {
        if (!this.#bot) return;
        await this.#bot.telegram.sendMessage(chatId, text.substring(0, 4096), {
            parse_mode: "Markdown",
        });
    }

    public async sendApprovalCard(
        senderId: string,
        title: string,
        body: string,
        approvalId: string
    ): Promise<void> {
        if (!this.#bot) return;
        const inlineKeyboard = [
            [
                { text: "✅ Approve", callback_data: `approve:${approvalId}` },
                { text: "❌ Reject", callback_data: `reject:${approvalId}` },
            ],
        ];

        await this.#bot.telegram.sendMessage(
            senderId,
            `🔐 *${title}*\n\n\`\`\`\n${body.substring(0, 3500)}\n\`\`\``,
            {
                parse_mode: "Markdown",
                reply_markup: { inline_keyboard: inlineKeyboard },
            }
        );
    }

    public async sendScreenshot(chatId: string, imageBuffer: Buffer): Promise<void> {
        if (!this.#bot) return;
        await this.#bot.telegram.sendPhoto(chatId, {
            source: imageBuffer,
            filename: "screenshot.png"
        });
    }

    public async editMessage(chatId: string, messageId: number, text: string): Promise<void> {
        if (!this.#bot) return;
        try {
            await this.#bot.telegram.editMessageText(
                chatId,
                messageId,
                undefined,
                text.substring(0, 4096),
                { parse_mode: "Markdown" }
            );
        } catch (e) {
            // Ignore "message is not modified" errors
        }
    }
