        if (!this.isZaloMessage(userText)) {
            return;
        }

        try {
            await this.#registry.executeSkill("send_zalo_bot", {
                message: "LIVA dang chuyen tac vu sang Expert 26B tren VRAM. Khong can reload toan bo he thong, vui long cho khoang 5s.",
