            const path1 = path.join(cwd, "data", "liva_vault.json");
            const path2 = path.join(cwd, "..", "data", "liva_vault.json");
            if (syncFs.existsSync(path1)) {
                vaultPath = path1;
            } else if (syncFs.existsSync(path2)) {
                vaultPath = path2;
            } else {
                vaultPath = path1;
            }
