class EmailClientManager {
    private client: ImapFlow | null = null;
    #reconnectTimer: ReturnType<typeof setTimeout> | null = null;
    private lastProcessedUID: number = 0;
    private retryCount: number = 0;
    private isRunning: boolean = false;
    private uidFilePath = path.join(process.cwd(), ".email_last_uid");
    #abortController: AbortController = new AbortController();

    private async loadLastUID() {
        try {
            const data = await fsp.readFile(this.uidFilePath, "utf-8");
            this.lastProcessedUID = parseInt(data, 10) || 0;
        } catch {
            this.lastProcessedUID = 0;
        }
    }

    private async saveLastUID() {
        try {
            const tmpPath = `${this.uidFilePath}.tmp`;
            await fsp.writeFile(tmpPath, this.lastProcessedUID.toString(), "utf-8");
            await safeRename(tmpPath, this.uidFilePath);
        } catch (e: unknown) {
        const errMsg = e instanceof Error ? e.message : String(e);
            logger.error(`[EmailClientManager] Lỗi lưu UID: ${errMsg}`);
        }
    }

    public async startIdling() {
        this.isRunning = true;
        await this.loadLastUID();
        await this.connectWithBackoff();
    }

    private async connectWithBackoff() {
        if (!this.isRunning) return;

        const host = process.env.EMAIL_HOST || "";
        const user = process.env.EMAIL_USER || "";
        const pass = process.env.EMAIL_PASS?.replace(/\s+/g, '') || "";

        if (!host || !user || !pass) {
            logger.warn("[EmailClientManager] Thiếu config Email (EMAIL_HOST, EMAIL_USER, EMAIL_PASS). Bỏ qua Ingress.");
            return;
        }

        // Detect if credentials failed to decrypt (AES-GCM format: iv:tag:ciphertext)
        if (host.includes(":") && host.length > 50) {
            logger.error("[EmailClientManager] 🚨 Mật khẩu/Host Email trong liva_vault.json chưa được giải mã thành công (sai LIVA_ENCRYPTION_KEY hoặc do mã hóa bởi hệ thống cũ). Đã tự ngắt kết nối để tránh lỗi Crash DNS!");
            this.isRunning = false; // Prevent retry loop
            return;
        }

        try {
            this.client = new ImapFlow({
                host,
                port: 993,
                secure: true,
                auth: { user, pass },
                logger: false // Mute default logs
            });

            // Monkey-patch emit to prevent ANY unhandled 'error' from crashing the process
            const originalEmit = this.client.emit.bind(this.client);
            this.client.emit = function(event: string | symbol, ...args: any[]) {
                if (event === 'error' && this.listenerCount('error') === 0) {
                    logger.error(`[EmailClientManager] Prevented unhandled ImapFlow error: ${args[0]?.message}`);
                    return false;
                }
                return originalEmit(event, ...args);
            };

            // Prevent Unhandled 'error' event from crashing the Node.js process
            this.client.on('error', (err: Error) => {
                logger.error(`[EmailClientManager] Lỗi nền ImapFlow: ${err.message}`);
                this.triggerReconnect();
            });

            await this.client.connect();
            logger.info("[EmailClientManager] IMAP Connected. Bắt đầu theo dõi inbox.");
            this.retryCount = 0; // Reset backoff

            // Process existing new emails first (simplified for boilerplate)
            await this.processNewEmails();

            const lock = await this.client.getMailboxLock('INBOX');
            try {
                this.client.on('exists', () => {
                    this.processNewEmails().catch(e => logger.error(`[EmailClientManager] Lỗi xử lý mail: ${e.message}`));
                });

                this.client.on('close', () => {
                    logger.warn("[EmailClientManager] IMAP connection closed by server. Reconnecting...");
                    this.triggerReconnect();
                });
            } finally {
                // We hold the lock while idling
                lock.release();
            }
        } catch (e: unknown) {
        const errMsg = e instanceof Error ? e.message : String(e);
            logger.error(`[EmailClientManager] Lỗi kết nối IMAP: ${errMsg}`);
            this.triggerReconnect();
        }
    }

    private triggerReconnect() {
        if (!this.isRunning) return;
        if (this.client) {
            const oldClient = this.client;
            oldClient.close();
            // Prevent delayed socket errors from crashing Node after client is closed
            oldClient.on('error', () => {});
            this.client = null;
        }

        const delay = Math.min(Math.pow(2, this.retryCount) * 1000, 60000); // Max 60s
        this.retryCount++;
        logger.info(`[EmailClientManager] Reconnecting in ${delay}ms (Attempt ${this.retryCount})`);

        // Guard: clear any existing timer before scheduling a new one
        if (this.#reconnectTimer) clearTimeout(this.#reconnectTimer);
        this.#reconnectTimer = setTimeout(() => {
            this.connectWithBackoff();
        }, delay);
    }

    public sanitizeHTML(html: string): string {
        return html.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '') // Remove scripts
                   .replace(/<[^>]*>?/gm, ' ') // Remove all HTML tags
                   .replace(/\s+/g, ' ') // Collapse spaces
                   .trim();
    }

    private async processNewEmails() {
        if (!this.client) return;
        
        try {
            // Logic lấy mail mới nhất (Giả lập logic iterator của imapflow)
            for await (const msg of this.client.fetch({ uid: `${this.lastProcessedUID + 1}:*` }, { uid: true, source: true })) {
                if (msg.uid <= this.lastProcessedUID) continue;

                const rawBody = msg.source ? msg.source.toString('utf-8') : "";
                const sanitizedText = this.sanitizeHTML(rawBody);
                
                // Đóng gói Event Brick
                logger.info(`[EmailClientManager] Received email UID ${msg.uid}`);
                
                this.lastProcessedUID = Math.max(this.lastProcessedUID, msg.uid);
            }
            await this.saveLastUID();
        } catch (e: unknown) {
        const errMsg = e instanceof Error ? e.message : String(e);
            logger.error(`[EmailClientManager] Fetch failed: ${errMsg}`);
        }
    }

    public dispose() {
        this.isRunning = false;
        if (this.#reconnectTimer) {
            clearTimeout(this.#reconnectTimer);
            this.#reconnectTimer = null;
        }
        if (this.client) {
            const oldClient = this.client;
            oldClient.logout().catch(() => {});
            oldClient.on('error', () => {});
            this.client = null;
        }
        this.#abortController.abort();
        this.#abortController = new AbortController();
        logger.info("[EmailClientManager] Disposed an toàn.");
    }
}

