        try {
            this.#deps.pushNotification(
                "🧘 Nhắc nghỉ ngơi",
                `Bạn đã làm việc liên tục ${timeStr}. Hãy đứng dậy vươn vai, uống nước và nghỉ mắt ${this.#breakDurationMs / 60_000} phút nhé!`,
