class WhisperNode extends EventEmitter {
  private audioBuffer: Buffer[] = [];
  private isProcessing: boolean = false;
  #silenceTimer: NodeJS.Timeout | null = null;

  // ── Circuit Breaker (v25 Anti-DDoS) ──
  /** Prevents spamming requests to a failing Whisper server */
  #isCircuitOpen: boolean = false;
  #consecutiveFailures: number = 0;
  #circuitTimer: NodeJS.Timeout | null = null;
  private readonly CIRCUIT_THRESHOLD = 3;      // Open circuit after 3 failures
  private readonly CIRCUIT_RESET_MS = 15000;    // Auto-reset after 15 seconds
  
  // Ngưỡng 800ms để quyết định người dùng đã kết thúc câu (Endpointing)
  // [v22] This timer will be REPLACED by VADWorkerBridge when SmartTurnVAD is wired.
  // For now, it serves as a fallback for environments without Silero ONNX model.
  private readonly VAD_SILENCE_MS = 800; 

  constructor() {
    super();
    logger.info(`[WhisperNode] Khởi tạo Hệ thống Thính giác (STT). Chờ tín hiệu Float32 PCM.`);
  }

  // ═══════════════════════════════════════════════════════
  //  Circuit Breaker (v25 Anti-DDoS)
  // ═══════════════════════════════════════════════════════

  /**
   * [v25] Record a failure and potentially open the circuit breaker.
   * After 3 consecutive failures, blocks all further requests for 15 seconds.
   */
  #recordFailure(): void {
    this.#consecutiveFailures++;
    if (this.#consecutiveFailures >= this.CIRCUIT_THRESHOLD) {
      this.#isCircuitOpen = true;
      logger.error(`[WhisperNode] CIRCUIT OPEN — Too many failures (${this.#consecutiveFailures}). Blocking requests for ${this.CIRCUIT_RESET_MS / 1000}s.`);

      // Schedule circuit reset
      if (this.#circuitTimer) clearTimeout(this.#circuitTimer);
      this.#circuitTimer = setTimeout(() => {
        this.#isCircuitOpen = false;
        this.#consecutiveFailures = 0;
        this.#circuitTimer = null;
        logger.info(`[WhisperNode] Circuit reset — Whisper requests resumed.`);
      }, this.CIRCUIT_RESET_MS);
    }
  }

  /**
   * [v25] Record a successful request — reset failure counter.
   */
  #recordSuccess(): void {
    this.#consecutiveFailures = 0;
  }

  /**
   * Check if circuit breaker is open (service unavailable).
   */
  public isCircuitOpen(): boolean {
    return this.#isCircuitOpen;
  }

  // ═══════════════════════════════════════════════════════
  //  STT Pipeline (Main)
  // ═══════════════════════════════════════════════════════

  /**
   * Hứng luồng âm thanh Mic cực nhỏ bắn từ UIController
   * @param chunk Khối nhị phân PCM
   */
  public pushAudioChunk(chunk: Buffer) {
    this.audioBuffer.push(chunk);

    // Kích hoạt lại cơ chế đo đếm Khoảng lặng
    if (this.#silenceTimer) {
      clearTimeout(this.#silenceTimer);
    }
    this.#silenceTimer = setTimeout(() => {
        this.#silenceTimer = null;
        this.processAudioIntents();
    }, this.VAD_SILENCE_MS);
  }

  /**
   * [v26] Accumulate audio chunk WITHOUT triggering the silence timer.
   * Used when VADWorkerBridge is active — VAD controls transcription timing
   * via triggerTranscription(). Without this, audioBuffer stays empty and
   * speech-to-text returns "" on every utterance.
   * @param chunk Raw PCM audio buffer from frontend
   */
  public pushAudioChunkOnly(chunk: Buffer): void {
    this.audioBuffer.push(chunk);
  }

  /**
   * [v22] Called by VADWorkerBridge on "speech_end" event.
   * Immediately triggers transcription without waiting for silence timer.
   */
  public triggerTranscription(): void {
    if (this.#silenceTimer) {
      clearTimeout(this.#silenceTimer);
      this.#silenceTimer = null;
    }
    this.processAudioIntents();
  }

  /**
   * Trích xuất STT khi nhận diện khoảng lặng, theo kiến trúc VAD.
   */
  private async processAudioIntents() {
    if (this.audioBuffer.length === 0 || this.isProcessing) return;

    this.isProcessing = true;
    logger.debug(`[WhisperNode] Đoạt ngưỡng Silence Threshold. Đang nén VRAM để trích xuất Text...`);

    const fullBuffer = Buffer.concat(this.audioBuffer);
    this.audioBuffer = []; // Wipe the buffer for the next sentence

    try {
      // Thay vì giả lập, gởi thẳng luồng Audio vào mô hình Whisper
      // Chúng ta sẽ ép buffer Float32 PCM thành 16kHz 16-bit WAV (chuẩn bắt buộc của whisper.cpp)
      if (fullBuffer.length > 4096) {
         logger.info(`[WhisperNode] Đang đúc khuôn WAV và gọi xuống Whisper Core...`);
         
         const textResult = await this.realWhisperInference(fullBuffer);
         if (textResult) {
            logger.info(`[WhisperNode] Nhận dạng Giọng Nói: "${textResult}"`);
            this.emit("transcription_ready", textResult);
         }
      }
    } catch (e: unknown) {
      const errMsg = e instanceof Error ? e.message : String(e);
      logger.error(`[WhisperNode] Sụp đổ luồng ASR: ${errMsg}`);
    } finally {
      this.isProcessing = false;
      // [FIX MUTE BUG] Reschedule processing if data arrived and timer was dropped during isProcessing
      if (this.audioBuffer.length > 0 && !this.#silenceTimer) {
          logger.debug(`[WhisperNode] 🔄 Tự động xử lý luồng âm thanh tồn đọng sau khi ASR rảnh...`);
          this.#silenceTimer = setTimeout(() => {
              this.#silenceTimer = null;
              this.processAudioIntents();
          }, 50);
      }
    }
  }

  /**
   * [v22 Pillar 3] Resolve Whisper endpoint based on hardware profile.
   * [v25] Updated: Default port changed to 8100 (Python Native Engine).
   *
   * Decision Tree:
   *   WHISPER_URL set?          → Use it (explicit override)
   *   AI_PROVIDER = "local"?    → Use WHISPER_CLOUD_URL (keep GPU for LLM)
   *                                Fallback to local if no cloud URL configured.
   *   AI_PROVIDER = "cloud"?    → Use local Whisper (GPU is free)
   */
  #resolveWhisperEndpoint(): string {
    // 1. Explicit override
    if (process.env.WHISPER_URL) {
      return process.env.WHISPER_URL;
    }

    // 2. Hardware-asymmetric routing
    const isLocalLLM = ConfigManager.getInstance().aiProvider === "local";

    if (isLocalLLM && ConfigManager.getInstance().env.WHISPER_CLOUD_URL) {
      // LLM is hogging local GPU → route STT to cloud
      logger.debug("[WhisperNode] Routing STT to Cloud (GPU reserved for local LLM)");
      return ConfigManager.getInstance().env.WHISPER_CLOUD_URL!;
    }

    // 3. Default: Python Native Engine on port 8100
    return "http://127.0.0.1:8100/v1/audio/transcriptions";
  }

  /**
   * [v25] Check if endpoint is a cloud service (needs Authorization header).
   * Cloud endpoints don't contain localhost/127.0.0.1.
   */
  #isCloudEndpoint(endpoint: string): boolean {
    return !endpoint.includes("localhost") && !endpoint.includes("127.0.0.1");
  }

  /**
   * [v25] Build fetch headers based on endpoint type.
   * Cloud endpoints require Bearer token authentication.
   */
  #buildRequestHeaders(endpoint: string): Record<string, string> {
    const headers: Record<string, string> = {};

    if (this.#isCloudEndpoint(endpoint)) {
      // Cloud endpoint: require Authorization header
      const apiKey = ConfigManager.getInstance().env.AI_API_KEY;
      if (apiKey) {
        headers["Authorization"] = `Bearer ${apiKey}`;
        logger.debug("[WhisperNode] Using Bearer auth for cloud STT endpoint");
      } else {
        logger.warn("[WhisperNode] Cloud STT endpoint configured but AI_API_KEY is missing!");
      }
    }

    return headers;
  }

  /**
   * Đúc File WAV trên RAM và đút vào mồm Whisper qua IPC Http
   */
  private async realWhisperInference(pcmFloat32Buffer: Buffer): Promise<string> {
    // [v25] Circuit Breaker: If service is failing, reject immediately
    if (this.#isCircuitOpen) {
      logger.warn("[WhisperNode] Circuit is OPEN — skipping Whisper request (service unavailable)");
      return "";
    }

    // 1. Chuyển Buffer JS thành Float32Array
    const float32Arr = new Float32Array(
      pcmFloat32Buffer.buffer, 
      pcmFloat32Buffer.byteOffset, 
      pcmFloat32Buffer.byteLength / 4
    );

    // 2. Ép kiểu chuẩn WAV Mono 16-bit 16000Hz PCM Encoding
    const sampleRate = 16000;
    const wavBuffer = Buffer.alloc(44 + float32Arr.length * 2);
    
    // Header WAV 44 byte chuẩn
    wavBuffer.write("RIFF", 0);
    wavBuffer.writeUInt32LE(36 + float32Arr.length * 2, 4);
    wavBuffer.write("WAVE", 8);
    wavBuffer.write("fmt ", 12);
    wavBuffer.writeUInt32LE(16, 16); 
    wavBuffer.writeUInt16LE(1, 20); 
    wavBuffer.writeUInt16LE(1, 22); 
    wavBuffer.writeUInt32LE(sampleRate, 24); 
    wavBuffer.writeUInt32LE(sampleRate * 2, 28); 
    wavBuffer.writeUInt16LE(2, 32); 
    wavBuffer.writeUInt16LE(16, 34); 
    wavBuffer.write("data", 36);
    wavBuffer.writeUInt32LE(float32Arr.length * 2, 40);

    // Bơm float32 nén thành int16
    let offset = 44;
    for (let i = 0; i < float32Arr.length; i++) {
        const s = Math.max(-1, Math.min(1, float32Arr[i]));
        wavBuffer.writeInt16LE(s < 0 ? s * 0x8000 : s * 0x7FFF, offset);
        offset += 2;
    }

    // 3. Giao tiếp Zero-Copy Form Data -> Liva Whisper Inference
    const blob = new Blob([wavBuffer], { type: "audio/wav" });
    const fd = new FormData();
    fd.append('file', blob, 'liva_realtime_transcribe.wav');
    fd.append('response_format', 'text');

    // [v22] Asymmetric endpoint routing
    const whisperEndpoint = this.#resolveWhisperEndpoint();
    const headers = this.#buildRequestHeaders(whisperEndpoint);

    try {
        // safeFetch with 30s timeout (Whisper inference can be slow)
        const { safeFetch } = await import("../utils/HttpClient");
        const response = await safeFetch(whisperEndpoint, {
            method: 'POST',
            body: fd,
            headers
        }, 30000);

        if (!response.ok) {
            throw new Error(`Whisper API trả về mã lỗi: ${response.status} ${response.statusText}`);
        }

        const textResponse = await response.text();
        this.#recordSuccess();  // Reset failure counter on success
        return textResponse.trim();
    } catch (err: unknown) {
      // Extract ECONNREFUSED correctly per AI_CONTEXT.md Rule 4.1
      const errMsg = err instanceof Error ? ((err as any).cause?.message || err.message) : String(err);
        logger.error(`[WhisperNode] Mất kết nối tới Whisper Engine: ${errMsg}`);
        this.#recordFailure();  // Increment failure counter, may open circuit
        return "";
    }
  }

  /**
   * Trạng thái Barge-in khẩn cấp để đánh giá ngắt luồng
   */
  public flush() {
    this.audioBuffer = [];
    if (this.#silenceTimer) clearTimeout(this.#silenceTimer);
    this.isProcessing = false;
    logger.debug(`[WhisperNode] Buffer flushed due to Preemption.`);
  }

  /**
   * Full cleanup — matches WhisperJSNode interface
   */
  public destroy() {
    logger.info(`[WhisperNode] Disposing STT engine...`);
    this.flush();
    // Clear circuit breaker timer
    if (this.#circuitTimer) {
      clearTimeout(this.#circuitTimer);
      this.#circuitTimer = null;
    }
    this.#isCircuitOpen = false;
    this.#consecutiveFailures = 0;
    this.removeAllListeners();
  }
}

constructor() {
    super();
    logger.info(`[WhisperNode] Khởi tạo Hệ thống Thính giác (STT). Chờ tín hiệu Float32 PCM.`);
  }

#recordFailure(): void {
    this.#consecutiveFailures++;
    if (this.#consecutiveFailures >= this.CIRCUIT_THRESHOLD) {
      this.#isCircuitOpen = true;
      logger.error(`[WhisperNode] CIRCUIT OPEN — Too many failures (${this.#consecutiveFailures}). Blocking requests for ${this.CIRCUIT_RESET_MS / 1000}s.`);

      // Schedule circuit reset
      if (this.#circuitTimer) clearTimeout(this.#circuitTimer);
      this.#circuitTimer = setTimeout(() => {
        this.#isCircuitOpen = false;
        this.#consecutiveFailures = 0;
        this.#circuitTimer = null;
        logger.info(`[WhisperNode] Circuit reset — Whisper requests resumed.`);
      }, this.CIRCUIT_RESET_MS);
    }
  }

#recordSuccess(): void {
    this.#consecutiveFailures = 0;
  }

public isCircuitOpen(): boolean {
    return this.#isCircuitOpen;
  }

public pushAudioChunk(chunk: Buffer) {
    this.audioBuffer.push(chunk);

    // Kích hoạt lại cơ chế đo đếm Khoảng lặng
    if (this.#silenceTimer) {
      clearTimeout(this.#silenceTimer);
    }
    this.#silenceTimer = setTimeout(() => {
        this.#silenceTimer = null;
        this.processAudioIntents();
    }, this.VAD_SILENCE_MS);
  }

public pushAudioChunkOnly(chunk: Buffer): void {
    this.audioBuffer.push(chunk);
  }

public triggerTranscription(): void {
    if (this.#silenceTimer) {
      clearTimeout(this.#silenceTimer);
      this.#silenceTimer = null;
    }
    this.processAudioIntents();
  }

private async processAudioIntents() {
    if (this.audioBuffer.length === 0 || this.isProcessing) return;

    this.isProcessing = true;
    logger.debug(`[WhisperNode] Đoạt ngưỡng Silence Threshold. Đang nén VRAM để trích xuất Text...`);

    const fullBuffer = Buffer.concat(this.audioBuffer);
    this.audioBuffer = []; // Wipe the buffer for the next sentence

    try {
      // Thay vì giả lập, gởi thẳng luồng Audio vào mô hình Whisper
      // Chúng ta sẽ ép buffer Float32 PCM thành 16kHz 16-bit WAV (chuẩn bắt buộc của whisper.cpp)
      if (fullBuffer.length > 4096) {
         logger.info(`[WhisperNode] Đang đúc khuôn WAV và gọi xuống Whisper Core...`);
         
         const textResult = await this.realWhisperInference(fullBuffer);
         if (textResult) {
            logger.info(`[WhisperNode] Nhận dạng Giọng Nói: "${textResult}"`);
            this.emit("transcription_ready", textResult);
         }
      }
    } catch (e: unknown) {
      const errMsg = e instanceof Error ? e.message : String(e);
      logger.error(`[WhisperNode] Sụp đổ luồng ASR: ${errMsg}`);
    } finally {
      this.isProcessing = false;
      // [FIX MUTE BUG] Reschedule processing if data arrived and timer was dropped during isProcessing
      if (this.audioBuffer.length > 0 && !this.#silenceTimer) {
          logger.debug(`[WhisperNode] 🔄 Tự động xử lý luồng âm thanh tồn đọng sau khi ASR rảnh...`);
          this.#silenceTimer = setTimeout(() => {
              this.#silenceTimer = null;
              this.processAudioIntents();
          }, 50);
      }
    }
  }

#resolveWhisperEndpoint(): string {
    // 1. Explicit override
    if (process.env.WHISPER_URL) {
      return process.env.WHISPER_URL;
    }

    // 2. Hardware-asymmetric routing
    const isLocalLLM = ConfigManager.getInstance().aiProvider === "local";

    if (isLocalLLM && ConfigManager.getInstance().env.WHISPER_CLOUD_URL) {
      // LLM is hogging local GPU → route STT to cloud
      logger.debug("[WhisperNode] Routing STT to Cloud (GPU reserved for local LLM)");
      return ConfigManager.getInstance().env.WHISPER_CLOUD_URL!;
    }

    // 3. Default: Python Native Engine on port 8100
    return "http://127.0.0.1:8100/v1/audio/transcriptions";
  }

#isCloudEndpoint(endpoint: string): boolean {
    return !endpoint.includes("localhost") && !endpoint.includes("127.0.0.1");
  }

#buildRequestHeaders(endpoint: string): Record<string, string> {
    const headers: Record<string, string> = {};

    if (this.#isCloudEndpoint(endpoint)) {
      // Cloud endpoint: require Authorization header
      const apiKey = ConfigManager.getInstance().env.AI_API_KEY;
      if (apiKey) {
        headers["Authorization"] = `Bearer ${apiKey}`;
        logger.debug("[WhisperNode] Using Bearer auth for cloud STT endpoint");
      } else {
        logger.warn("[WhisperNode] Cloud STT endpoint configured but AI_API_KEY is missing!");
      }
    }

    return headers;
  }

private async realWhisperInference(pcmFloat32Buffer: Buffer): Promise<string> {
    // [v25] Circuit Breaker: If service is failing, reject immediately
    if (this.#isCircuitOpen) {
      logger.warn("[WhisperNode] Circuit is OPEN — skipping Whisper request (service unavailable)");
      return "";
    }

    // 1. Chuyển Buffer JS thành Float32Array
    const float32Arr = new Float32Array(
      pcmFloat32Buffer.buffer, 
      pcmFloat32Buffer.byteOffset, 
      pcmFloat32Buffer.byteLength / 4
    );

    // 2. Ép kiểu chuẩn WAV Mono 16-bit 16000Hz PCM Encoding
    const sampleRate = 16000;
    const wavBuffer = Buffer.alloc(44 + float32Arr.length * 2);
    
    // Header WAV 44 byte chuẩn
    wavBuffer.write("RIFF", 0);
    wavBuffer.writeUInt32LE(36 + float32Arr.length * 2, 4);
    wavBuffer.write("WAVE", 8);
    wavBuffer.write("fmt ", 12);
    wavBuffer.writeUInt32LE(16, 16); 
    wavBuffer.writeUInt16LE(1, 20); 
    wavBuffer.writeUInt16LE(1, 22); 
    wavBuffer.writeUInt32LE(sampleRate, 24); 
    wavBuffer.writeUInt32LE(sampleRate * 2, 28); 
    wavBuffer.writeUInt16LE(2, 32); 
    wavBuffer.writeUInt16LE(16, 34); 
    wavBuffer.write("data", 36);
    wavBuffer.writeUInt32LE(float32Arr.length * 2, 40);

    // Bơm float32 nén thành int16
    let offset = 44;
    for (let i = 0; i < float32Arr.length; i++) {
        const s = Math.max(-1, Math.min(1, float32Arr[i]));
        wavBuffer.writeInt16LE(s < 0 ? s * 0x8000 : s * 0x7FFF, offset);
        offset += 2;
    }

    // 3. Giao tiếp Zero-Copy Form Data -> Liva Whisper Inference
    const blob = new Blob([wavBuffer], { type: "audio/wav" });
    const fd = new FormData();
    fd.append('file', blob, 'liva_realtime_transcribe.wav');
    fd.append('response_format', 'text');

    // [v22] Asymmetric endpoint routing
    const whisperEndpoint = this.#resolveWhisperEndpoint();
    const headers = this.#buildRequestHeaders(whisperEndpoint);

    try {
        // safeFetch with 30s timeout (Whisper inference can be slow)
        const { safeFetch } = await import("../utils/HttpClient");
        const response = await safeFetch(whisperEndpoint, {
            method: 'POST',
            body: fd,
            headers
        }, 30000);

        if (!response.ok) {
            throw new Error(`Whisper API trả về mã lỗi: ${response.status} ${response.statusText}`);
        }

        const textResponse = await response.text();
        this.#recordSuccess();  // Reset failure counter on success
        return textResponse.trim();
    } catch (err: unknown) {
      // Extract ECONNREFUSED correctly per AI_CONTEXT.md Rule 4.1
      const errMsg = err instanceof Error ? ((err as any).cause?.message || err.message) : String(err);
        logger.error(`[WhisperNode] Mất kết nối tới Whisper Engine: ${errMsg}`);
        this.#recordFailure();  // Increment failure counter, may open circuit
        return "";
    }
  }

public flush() {
    this.audioBuffer = [];
    if (this.#silenceTimer) clearTimeout(this.#silenceTimer);
    this.isProcessing = false;
    logger.debug(`[WhisperNode] Buffer flushed due to Preemption.`);
  }

public destroy() {
    logger.info(`[WhisperNode] Disposing STT engine...`);
    this.flush();
    // Clear circuit breaker timer
    if (this.#circuitTimer) {
      clearTimeout(this.#circuitTimer);
      this.#circuitTimer = null;
    }
    this.#isCircuitOpen = false;
    this.#consecutiveFailures = 0;
    this.removeAllListeners();
  }

class SkillRegistry {
  private readonly mcpManager: MCPClientManager;
  private mcpToolsList: any[] = [];
  private fallbackSkills: Map<string, AgentSkill> = new Map();
  private localMcpClient?: Client;
  /** Skill metadata from LocalMCPServer (search_keywords, isCoreSkill, kit, etc.) */
  private localSkillMeta: Map<string, AgentSkill> = new Map();

  /**
   * LRU-cached description embeddings — prevents re-embedding
   * 33 skills × 384D vector on each user turn.
   * TTL 1h: descriptions don't change at runtime.
   */
  private readonly descEmbeddingCache = new LRUCache<string, number[]>({
      max: 100,
      ttl: 3600000, // 1 hour
  });

  // [v25] Passive Circuit Breaker — tracks per-skill failures, prunes dead tools from context
  public readonly circuitBreaker = new SkillCircuitBreaker();

  // [v25] Skill Whitelist — user-controlled enablement (persisted to disk)
  public readonly whitelist = new SkillWhitelist();

  private static instance: SkillRegistry | null = null;

  public static getInstance(): SkillRegistry | null {
      return SkillRegistry.instance;
  }

  constructor() {
      this.mcpManager = MCPClientManager.getInstance();
      this.registerBuiltInSkills();
      SkillRegistry.instance = this;
  }

  public async registerLocalSkills() {
      // Clean up old local client connection to prevent event emitter & memory leaks
      if (this.localMcpClient) {
          try {
              await this.localMcpClient.close();
              logger.debug("[SkillRegistry] Cleanly disconnected previous Local MCP Client.");
          } catch (e) {
              logger.warn(`[SkillRegistry] Non-fatal error while closing old Local MCP Client: ${e}`);
          }
          this.localMcpClient = undefined;
      }

      try {
          const localMCPServer = new LocalMCPServer();
          await localMCPServer.loadSkills();
          
          const [clientTransport, serverTransport] = InMemoryTransport.createLinkedPair();
          
          await localMCPServer.getServerInstance().connect(serverTransport);
          
          this.localMcpClient = new Client(
              { name: "LIVA-Gateway-InProcess", version: "1.0.0" },
              { capabilities: {} }
          );
          
          await this.localMcpClient.connect(clientTransport);
          
          const response = await this.localMcpClient.listTools();
          // Add local tools with no _serverId or a specific local ID
          const localTools = response.tools.map(t => ({ ...t, _serverId: "liva-local-in-process" }));
          
          // Combine with any other tools from mcpManager (if there are external ones)
          const externalTools = await this.mcpManager.getAllConnectedTools();
          this.mcpToolsList = [...localTools, ...externalTools];

          // [CRITICAL] Store skill metadata (search_keywords, isCoreSkill, kit, etc.)
          // MCP protocol strips custom fields, so we preserve them via side-channel
          this.localSkillMeta = localMCPServer.getSkillMetadata();

          logger.info(`[SkillRegistry] In-process MCP Server initialized. Cached ${localTools.length} local tools + ${externalTools.length} external tools.`);
      } catch (e: unknown) {
          const errMsg = e instanceof Error ? e.message : String(e);
          logger.error(`[SkillRegistry] In-process MCP Init Error: ${errMsg}`);
      }
  }

  public registerSkill(skill: AgentSkill) {
      this.fallbackSkills.set(skill.name, skill);
  }

  public getAllSkills(): AgentSkill[] {
      const mcpSkills = this.mcpToolsList.map(tool => {
          // Enrich MCP tools with metadata that MCP protocol strips out
          const meta = this.localSkillMeta.get(tool.name);
          return {
              name: tool.name,
              description: tool.description,
              short_desc: meta?.short_desc || tool.description?.substring(0, 80),
              parameters: tool.inputSchema,
              search_keywords: meta?.search_keywords,
              isCoreSkill: meta?.isCoreSkill || false,
              category: meta?.category,
              semantic_tags: meta?.semantic_tags,
              kit: meta?.kit,
              requires_hitl: meta?.requires_hitl,
              is_cpu_heavy: meta?.is_cpu_heavy,
              _serverId: tool._serverId
          } as AgentSkill & { _serverId: string };
      });
      return [...mcpSkills, ...Array.from(this.fallbackSkills.values())];
  }

  /**
   * [v25] Get all skills EXCLUDING those with open circuit breakers.
   * Used by PromptBuilder to prevent injecting dead tools into LLM context.
   */
  public getHealthySkills(): AgentSkill[] {
      const openCircuits = new Set(this.circuitBreaker.getOpenCircuits());
      const disabledSkills = this.whitelist.getDisabledSkills();
      
      if (openCircuits.size === 0 && disabledSkills.size === 0) return this.getAllSkills();

      const healthy = this.getAllSkills().filter(s => 
          !openCircuits.has(s.name) && !disabledSkills.has(s.name)
      );

      if (openCircuits.size > 0) {
          logger.debug(`[v25 CircuitBreaker] Pruned ${openCircuits.size} dead skills: ${[...openCircuits].join(", ")}`);
      }
      if (disabledSkills.size > 0) {
          logger.debug(`[v25 Whitelist] Pruned ${disabledSkills.size} disabled skills: ${[...disabledSkills].join(", ")}`);
      }
      return healthy;
  }

  /**
   * Tool Attention — Semantic Top-K Filtering via EmbeddingService + Dynamic Gating
   * =============================================================
   * Pre-filters tools based on `activeKit` (Dynamic Gating) to prevent Prompt Bloat.
   * Then uses shared EmbeddingService singleton (all-MiniLM-L6-v2, 384D)
   * to compute cosine similarity between user query and remaining tool descriptions.
   *
   * DG-2: Dynamic Similarity Threshold (>0.65).
   *   If no tool exceeds threshold → returns [] (prevents hallucinated tool calls).
   *   CoreSkills always included regardless of threshold.
   *
   * @param userQuery  The user's raw text input
   * @param activeKit  The currently active kit detected by SemanticRouter
   * @param topK       Maximum non-core tools to return (default 3)
   * @returns          Filtered skills sorted by semantic relevance
   */
  public async getSemanticTopK(userQuery: string, activeKit?: import("./memory/SemanticRouter").SkillKit, topK: number = 3): Promise<AgentSkill[]> {
      // [v25] Use healthy skills only — exclude open circuit breakers
      let allSkills = this.getHealthySkills();

      // [Dynamic Gating] Phase 1: Filter by activeKit
      if (activeKit) {
          allSkills = allSkills.filter(s => s.isCoreSkill || s.kit === activeKit || s.kit === "GENERAL_KIT" || !s.kit);
      }

      // Fast-exit: if no query text, return core skills only
      if (!userQuery || userQuery.trim().length === 0) {
          return allSkills.filter(s => s.isCoreSkill);
      }

      const embedSvc = EmbeddingService.getInstance();

      // [CRITICAL] When EmbeddingService is using dummy vectors, cosine similarity
      // is meaningless (all skills get identical scores). Fall back to keyword-only matching.
      if (!embedSvc.ready) {
          logger.debug("[ToolAttention] EmbeddingService not ready — using keyword-only matching");
          const queryLower = userQuery.toLowerCase();
          const coreSkills: AgentSkill[] = [];
          const keywordMatched: AgentSkill[] = [];

          for (const skill of allSkills) {
              if (skill.isCoreSkill) {
                  coreSkills.push(skill);
                  continue;
              }
              const keywords = skill.search_keywords || [];
              const hasKeywordHit = keywords.some(kw =>
                  kw.length >= 2 && queryLower.includes(kw.toLowerCase())
              );
              if (hasKeywordHit) {
                  keywordMatched.push(skill);
              }
          }

          if (keywordMatched.length > 0) {
              logger.debug(`[ToolAttention] Keyword-only matched ${keywordMatched.length} tools: ${keywordMatched.map(s => s.name).join(", ")}`);
          }

          return [...coreSkills, ...keywordMatched.slice(0, topK)];
      }

      let queryVec: number[];
      try {
          queryVec = await embedSvc.embedWithTimeout(userQuery, 500);
      } catch {
          // Embedding failed — fallback to returning all skills (graceful degradation)
          logger.warn("[ToolAttention] Embedding failed, falling back to getAllSkills()");
          return allSkills;
      }

      const coreSkills: AgentSkill[] = [];
      const scored: Array<{ skill: AgentSkill; score: number }> = [];

      for (const skill of allSkills) {
          // CoreSkills always included (get_current_time, handoff_to_expert, etc.)
          if (skill.isCoreSkill) {
              coreSkills.push(skill);
              continue;
          }

          // Get or compute cached embedding for skill description
          let descVec = this.descEmbeddingCache.get(skill.name);
          if (!descVec) {
              const descText = `${skill.name} ${skill.search_keywords?.join(" ") || ""} ${skill.short_desc || skill.description.substring(0, 80)}`;
              try {
                  descVec = await embedSvc.embed(descText);
              } catch {
                  // [v25 FIX] embed() may throw mid-loop if VRAMGuard fires during processing.
                  // Skip this skill's semantic scoring — it won't appear in top-K results
                  // but coreSkills are still always included.
                  continue;
              }
              this.descEmbeddingCache.set(skill.name, descVec);
          }

          const score = cosineSimilarity(queryVec, descVec);
          scored.push({ skill, score });
      }

      // DG-2: Dynamic threshold — filter out low-confidence tools
      const qualified = scored
          .filter(s => s.score >= SIMILARITY_THRESHOLD)
          .sort((a, b) => b.score - a.score)
          .slice(0, topK);

      // [KEYWORD BOOST] Fallback for cross-lingual queries (Vietnamese → English embedding model)
      // If a skill has a search_keyword that exactly matches a substring in the user query,
      // include it even if cosine similarity is below threshold.
      const queryLower = userQuery.toLowerCase();
      const qualifiedNames = new Set(qualified.map(q => q.skill.name));
      const keywordBoosted: AgentSkill[] = [];

      for (const { skill, score } of scored) {
          const keywords = skill.search_keywords || [];
          const hasKeywordHit = keywords.some(kw =>
              kw.length >= 2 && queryLower.includes(kw.toLowerCase())
          );
          
          if (!hasKeywordHit && score < 0.30) continue; // Hard floor — skip completely irrelevant tools (unless exact keyword match)

          if (hasKeywordHit) {
              keywordBoosted.push(skill);
              logger.debug(`[ToolAttention/KeywordBoost] "${skill.name}" matched via keyword in query (cosine=${score.toFixed(3)})`);
          }
      }

      if (qualified.length > 0 || keywordBoosted.length > 0) {
          logger.debug(
              `[ToolAttention] Filtered ${allSkills.length} → ${coreSkills.length + qualified.length + keywordBoosted.length} tools ` +
              `(embedding: ${qualified.length}, keyword-boost: ${keywordBoosted.length})` +
              (qualified.length > 0 ? ` (top: ${qualified[0].skill.name}@${qualified[0].score.toFixed(3)})` : ``)
          );
      } else {
          logger.debug(`[ToolAttention] No tools above threshold ${SIMILARITY_THRESHOLD} — returning core only`);
      }

      return [...coreSkills, ...qualified.map(s => s.skill), ...keywordBoosted];
  }

  public async executeSkill(name: string, args: any): Promise<any> {
      logger.info(`[SkillRegistry] Đang thực thi kỹ năng qua MCP: ${name}`);

      if (!this.circuitBreaker.canExecute(name)) {
          logger.warn(`[CircuitBreaker] 🔌 Skill '${name}' đang bị NGẮT MẠCH (OPEN). Bỏ qua request.`);
          throw new Error(`Hệ thống mạng đang lỗi, hãy thử lại sau. (Skill: ${name})`);
      }

      try {
          const fallback = this.fallbackSkills.get(name);
          let rawResult;
          if (fallback) {
              rawResult = await fallback.execute!(args);
          } else {
              const tool = this.mcpToolsList.find(t => t.name === name);
              if (!tool) {
                  throw new Error(`MCP Tool '${name}' không tồn tại hoặc chưa kết nối!`);
              }

              let result;
              if (tool._serverId === "liva-local-in-process") {
                  if (!this.localMcpClient) throw new Error("Local MCP Client not initialized");
                  result = await this.localMcpClient.callTool({ name, arguments: args });
              } else {
                  result = await this.mcpManager.executeTool(tool._serverId, name, args);
              }
              
              const contentArray = result.content as { type: string, text: string }[] | undefined;
              
              if (result.isError) {
                  const textContent = contentArray?.[0]?.text || "Unknown MCP Error";
                  throw new Error(textContent);
              }
              
              rawResult = contentArray?.[0]?.text || "Success (No content)";
          }

          this.circuitBreaker.recordSuccess(name);
          return rawResult;
      } catch (error: unknown) {
          const errMsg = error instanceof Error ? error.message : String(error);
          this.circuitBreaker.recordFailure(name, errMsg);
          if (errMsg.includes("không tồn tại")) {
              throw error;
          }
          throw new Error(`MCP Tool '${name}' execution failed: ${errMsg}`);
      }
  }

  /**
   * Warm up the description embedding cache asynchronously in the background.
   * Runs after the AI models have loaded to avoid blocking the bootstrap sequence.
   */
  public async warmUpCache(): Promise<void> {
      logger.info("[SkillRegistry] ⏳ Warming up skill description embedding cache...");
      const start = performance.now();
      const healthySkills = this.getHealthySkills();
      const embedSvc = EmbeddingService.getInstance();

      // Ensure embedding service is ready
      try {
          await embedSvc.ensureReady();
      } catch (err) {
          logger.warn(`[SkillRegistry] Skipped warm-up: embedding service not ready. (${(err as Error).message})`);
          return;
      }

      const skillsToEmbed: AgentSkill[] = [];
      const textsToEmbed: string[] = [];

      for (const skill of healthySkills) {
          if (skill.isCoreSkill) continue;
          if (this.descEmbeddingCache.has(skill.name)) continue;

          const descText = `${skill.name} ${skill.search_keywords?.join(" ") || ""} ${skill.short_desc || skill.description.substring(0, 80)}`;
          skillsToEmbed.push(skill);
          textsToEmbed.push(descText);
      }

      if (textsToEmbed.length > 0) {
          try {
              const embeddings = await embedSvc.embedBatch(textsToEmbed);
              for (let i = 0; i < skillsToEmbed.length; i++) {
                  const vec = embeddings[i];
                  if (vec && Array.isArray(vec)) {
                      this.descEmbeddingCache.set(skillsToEmbed[i].name, vec);
                  }
              }
              const duration = performance.now() - start;
              logger.info(`[SkillRegistry] ✅ Cached ${textsToEmbed.length} skill embeddings in ${duration.toFixed(1)}ms.`);
          } catch (err) {
              logger.error(`[SkillRegistry] ❌ Skill cache warm-up failed: ${(err as Error).message}`);
          }
      } else {
          logger.info("[SkillRegistry] ✅ All skills already cached.");
      }
  }

  private registerBuiltInSkills() {
    this.registerSkill({
      name: "get_current_time",
      description: "[AUTO_RUN] Get current system date and time.",
      isCoreSkill: true,
      parameters: {
        type: "object",
        properties: { timezone: { type: "string" } },
      },
      execute: async (args: any) => {
        const date = new Date();
        if (args.timezone) return date.toLocaleString("vi-VN", { timeZone: args.timezone });
        return date.toLocaleString("vi-VN", { timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone });
      },
    });

    // --- GEMINI SURFER SKILL ---
    import('./skills/web/GeminiSurfer').then(geminiSurfer => {
      this.registerSkill({
        ...geminiSurfer.metadata,
        execute: geminiSurfer.execute
      });
    }).catch(e => logger.error(`[SkillRegistry] Lỗi nạp GeminiSurfer: ${e.message}`));
  }
}

