        for (const [id, data] of this.#activeTimers.entries()) {
            clearTimeout(data.timeout);
            logger.info(`[TimerReminder] Đã dọn dẹp timer zombie (ID: ${id}) do hệ thống shutdown.`);
        }
        this.#activeTimers.clear();
