async function getAudioSessions(): Promise<Array<{ name: string; volume: number }>> {
    const script = `${PS_GET_AUDIO_SESSIONS}\n[AudioMixer]::GetSessions()`;
    try {
        const { stdout } = await execAsync(`powershell.exe -NoProfile -Command "${script.replace(/"/g, '\\"').replace(/\n/g, '; ')}"`, {
            timeout: 10_000,
        });
        const lines = stdout.trim().split(/\r?\n/).filter(Boolean);
        const sessions: Array<{ name: string; volume: number }> = [];
        for (const line of lines) {
            const [name, volStr] = line.split("|");
            if (name === "ERROR") {
                logger.warn(`[AudioMixer] COM error: ${volStr}`);
                continue;
            }
            if (name && volStr) {
                sessions.push({ name: name.trim(), volume: parseFloat(volStr) });
            }
        }
        return sessions;
    } catch (err: unknown) {
        const errMsg = err instanceof Error ? err.message : String(err);
        logger.warn(`[AudioMixer] Không thể lấy audio sessions qua COM: ${errMsg}`);
        return [];
    }
}

async function setAppVolume(processName: string, volumeFloat: number): Promise<boolean> {
    const script = `${PS_GET_AUDIO_SESSIONS}\n[AudioMixer]::SetVolume('${processName}', ${volumeFloat.toFixed(2)})`;
    try {
        const { stdout } = await execAsync(`powershell.exe -NoProfile -Command "${script.replace(/"/g, '\\"').replace(/\n/g, '; ')}"`, {
            timeout: 10_000,
        });
        const result = stdout.trim();
        if (result === "OK") return true;
        if (result === "NOT_FOUND") {
            logger.warn(`[AudioMixer] Process '${processName}' không có audio session`);
            return false;
        }
        logger.warn(`[AudioMixer] SetVolume error: ${result}`);
        return false;
    } catch (err: unknown) {
        const errMsg = err instanceof Error ? err.message : String(err);
        logger.warn(`[AudioMixer] Lỗi set volume cho ${processName}: ${errMsg}`);
        return false;
    }
}

async function setMasterVolumeFallback(percent: number): Promise<void> {
    const upSteps = Math.round(percent / 2);
    const psScript = `
        $obj = new-object -com wscript.shell
        for ($i = 0; $i -lt 50; $i++) { $obj.SendKeys([char]174) }
        for ($i = 0; $i -lt ${upSteps}; $i++) { $obj.SendKeys([char]175) }
    `.replace(/\n/g, ";");
    await execAsync(`powershell.exe -NoProfile -Command "${psScript}"`);
}

function grantConsent(categories: { activeWindow?: boolean; clipboard?: boolean }): void {
  if (categories.activeWindow !== undefined) _consentState.activeWindow = categories.activeWindow;
  if (categories.clipboard !== undefined) _consentState.clipboard = categories.clipboard;
  _consentState.updatedAt = Date.now();
}

function revokeConsent(categories?: { activeWindow?: boolean; clipboard?: boolean }): void {
  if (!categories) { _consentState = { activeWindow: false, clipboard: false, updatedAt: Date.now() }; }
  else {
    if (categories.activeWindow === false) _consentState.activeWindow = false;
    if (categories.clipboard === false) _consentState.clipboard = false;
    _consentState.updatedAt = Date.now();
  }
}

async function extractPageContent(page: Page, maxLength: number = 3000): Promise<string> {
    try {
        const content = await page.evaluate(() => {
            // Remove script, style, nav elements
            const elementsToRemove = document.querySelectorAll("script, style, nav, footer, header, aside, iframe");
            elementsToRemove.forEach(el => el.remove());

            const body = document.body;
            if (!body) return "";

            // Get text content, clean up whitespace
            let text = body.innerText || body.textContent || "";
            text = text.replaceAll(/\n{3,}/g, "\n\n").trim();
            return text;
        });

        const title = await page.title();
        const url = page.url();

        let result = `[Trang web: ${title}]\n[URL: ${url}]\n\n`;
        result += content.substring(0, maxLength);
        if (content.length > maxLength) {
            result += "\n\n... (Nội dung đã được cắt ngắn để tiết kiệm token)";
        }
        return result;
    } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e);
        return `[Lỗi đọc trang]: ${errMsg}`;
    }
}

async function fetchUrlContent(url: string): Promise<string> {
  const response = await safeFetch(url, {
    headers: { "User-Agent": "LIVA-Bot/1.0 (Content Summarizer)" },
  }, 15000);

  const html = await response.text();

  // Strip HTML tags — lightweight extraction
  const text = html
    .replaceAll(/<script[^>]*>[\s\S]*?<\/script>/gi, "")
    .replaceAll(/<style[^>]*>[\s\S]*?<\/style>/gi, "")
    .replaceAll(/<nav[^>]*>[\s\S]*?<\/nav>/gi, "")
    .replaceAll(/<footer[^>]*>[\s\S]*?<\/footer>/gi, "")
    .replaceAll(/<header[^>]*>[\s\S]*?<\/header>/gi, "")
    .replaceAll(/<[^>]+>/g, " ")
    .replaceAll(/\s+/g, " ")
    .trim();

  return text;
}

async function fallbackDuckDuckGo(query: string): Promise<string> {
  const url = `https://html.duckduckgo.com/html/?q=${encodeURIComponent(query)}`;
  const response = await safeFetch(url, {
    headers: {
      "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)",
    },
  }, 10000);

  const html = await response.text();
  const results: { title: string; link: string }[] = [];
  const resultRegex = /<a class="result__url" href="([^"]+)">([^<]+)<\/a>/g;

  let match;
  while ((match = resultRegex.exec(html)) !== null && results.length < 10) {
    let link = match[1];
    if (link.startsWith("//duckduckgo.com/l/?uddg=")) {
      try {
        link = decodeURIComponent(link.split("uddg=")[1].split("&")[0]);
      } catch (e: unknown) {
        logger.warn(`[WebSearch] Không thể giải mã link DuckDuckGo: ${e instanceof Error ? e.message : String(e)}`);
      }
    }
    results.push({ link, title: match[2].trim() });
  }

  if (results.length === 0) {
    return `Không tìm thấy kết quả nào trên web cho "${query}".`;
  }

  let output = `[Web Search — DuckDuckGo Fallback] Top ${results.length} bài viết cho "${query}":\n`;
  results.forEach((r, i) => {
    output += `${i + 1}. ${r.title}\n   Link: ${r.link}\n`;
  });
  return output;
}

async function searchTavily(query: string): Promise<string> {
  const response = await safeFetch(TAVILY_ENDPOINT, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      api_key: TAVILY_API_KEY,
      query,
      search_depth: "basic",
      include_answer: true,
      include_raw_content: false,
      max_results: 5,
    }),
  }, 15000);

  const data = await response.json() as {
    answer?: string;
    results?: Array<{
      title: string;
      url: string;
      content: string;
      score: number;
    }>;
  };

  let output = `[Web Search — Tavily] Kết quả cho "${query}":\n\n`;

  // Tavily's AI-generated answer summary
  if (data.answer) {
    output += `📝 Tóm tắt AI: ${data.answer}\n\n`;
  }

  // Individual results
  if (data.results && data.results.length > 0) {
    output += `📰 Top ${data.results.length} nguồn:\n`;
    for (let i = 0; i < data.results.length; i++) {
      const r = data.results[i];
      output += `${i + 1}. ${r.title}\n`;
      output += `   ${r.content.substring(0, 200)}\n`;
      output += `   🔗 ${r.url}\n\n`;
    }
  }

  return output;
}

