async function authorize(): Promise<void> {
  try {
    await fs.access(CREDENTIALS_PATH);
  } catch {
    logger.error(
      { context: "auth_google_script", path: CREDENTIALS_PATH },
      `🚨 Không tìm thấy file credentials.json`
    );
    logger.info(
      { context: "auth_google_script" },
      `Vui lòng tải file OAuth2 Client từ Google Cloud Console và đổi tên thành credentials.json`
    );
    process.exit(1);
  }

  const content = await fs.readFile(CREDENTIALS_PATH, "utf8");
  const credentials = JSON.parse(content);

  if (credentials.type === "service_account") {
    logger.info(
      { context: "auth_google_script" },
      `✅ Bạn đang dùng Service Account, không cần chạy script này để lấy token. LIVA đã có thể hoạt động ngay.`
    );
    process.exit(0);
  }

  const { client_secret, client_id, redirect_uris } =
    credentials.installed || credentials.web;
  const oAuth2Client = new google.auth.OAuth2(
    client_id,
    client_secret,
    redirect_uris[0] || "http://localhost:3000"
  );

  logger.info({ context: "auth_google_script" }, `🔗 Đang tạo URL xác thực...`);
  const authUrl = oAuth2Client.generateAuthUrl({
    access_type: "offline",
    prompt: "consent",
    scope: SCOPES,
  });

  logger.info({ context: "auth_google_script" }, `\n======================================================`);
  logger.info({ context: "auth_google_script" }, `👉 BƯỚC 1: Hãy mở địa chỉ sau trên trình duyệt để cấp quyền:`);
  logger.info({ context: "auth_google_script" }, `${authUrl}`);
  logger.info({ context: "auth_google_script" }, `======================================================\n`);

  if (
    redirect_uris &&
    redirect_uris.some((r: string) => r.includes("localhost"))
  ) {
    const portObj = new URL(
      redirect_uris.find((r: string) => r.includes("localhost"))
    );
    const port = portObj.port || 3000;
    logger.info(
      { context: "auth_google_script", port },
      `👂 Đang lắng nghe phản hồi tại cổng ${port}...`
    );

    const server = http.createServer(async (req, res) => {
      try {
        if (req.url && req.url.indexOf("code=") > -1) {
          const qs = new URL(req.url, "http://localhost:3000").searchParams;
          const code = qs.get("code");
          logger.info(
            { context: "auth_google_script" },
            `✅ BƯỚC 2: Đã nhận được mã xác thực (code). Đang lấy Token...`
          );
          res.end(
            "<h1>LIVA Authentication Successful!</h1><p>You can close this tab and return to the terminal.</p>"
          );
          server.close();

          if (code) {
            const { tokens } = await oAuth2Client.getToken(code);
            oAuth2Client.setCredentials(tokens);
            await atomicWriteFile(TOKEN_PATH, JSON.stringify(tokens));
            logger.info(
              { context: "auth_google_script", path: TOKEN_PATH },
              `🎉 Xác thực thành công! Đã lưu token tại ${TOKEN_PATH}`
            );
            process.exit(0);
          }
        }
      } catch (err) {
        const errMsg = err instanceof Error ? err.message : String(err);
        logger.error(
          { context: "auth_google_script", error: errMsg },
          `❌ Lỗi khi lấy token`
        );
        res.end("<h1>LIVA Authentication Flow Failed!</h1>");
        server.close();
        process.exit(1);
      }
    });
    server.listen(port);
  } else {
    logger.info(
      { context: "auth_google_script" },
      `👉 BƯỚC 2: (Do không dùng localhost redirect) Sau khi đăng nhập, copy cái 'code' vào đây.`
    );
    const readline = await import("node:readline");
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });

    rl.question("Nhập code: ", async (code: string) => {
      try {
        const { tokens } = await oAuth2Client.getToken(code);
        oAuth2Client.setCredentials(tokens);
        await atomicWriteFile(TOKEN_PATH, JSON.stringify(tokens));
        logger.info(
          { context: "auth_google_script", path: TOKEN_PATH },
          `🎉 Xác thực thành công! Đã lưu token tại ${TOKEN_PATH}`
        );
      } catch (err) {
        const errMsg = err instanceof Error ? err.message : String(err);
        logger.error(
          { context: "auth_google_script", error: errMsg },
          `❌ Lỗi khi lấy token`
        );
      }
      rl.close();
    });
  }
}

function parseAxTree(
    rawNodes: RawAxNode[],
    options: {
        /** Include non-interactive semantic elements (headings, images) */
        includeSemanticNodes?: boolean;
        /** Maximum number of elements to return */
        maxElements?: number;
        /** Minimum name length to include (filters empty-name noise) */
        minNameLength?: number;
    } = {}
): AxElement[] {
    const {
        includeSemanticNodes = true,
        maxElements = 200,
        minNameLength = 1,
    } = options;

    const elements: AxElement[] = [];
    let nextId = 1;

    // Build parent depth map for tree pruning
    const depthMap = new Map<string, number>();
    const rootNodes = rawNodes.filter(n => !n.parentId);
    for (const root of rootNodes) {
        depthMap.set(root.nodeId, 0);
    }

    // BFS to calculate depths
    const queue = [...rootNodes];
    while (queue.length > 0) {
        const node = queue.shift()!;
        const parentDepth = depthMap.get(node.nodeId) ?? 0;

        if (node.childIds) {
            for (const childId of node.childIds) {
                depthMap.set(childId, parentDepth + 1);
                const child = rawNodes.find(n => n.nodeId === childId);
                if (child) queue.push(child);
            }
        }
    }

    for (const node of rawNodes) {
        // Skip ignored nodes
        if (node.ignored) continue;

        const role = node.role?.value ?? "";

        // Skip noise roles
        if (IGNORED_ROLES.has(role)) continue;

        // Determine if this node is worth including
        const isInteractive = INTERACTIVE_ROLES.has(role);
        const isSemantic = SEMANTIC_ROLES.has(role);

        if (!isInteractive && !(includeSemanticNodes && isSemantic)) continue;

        // Extract name
        const name = (node.name?.value ?? "").trim();

        // Skip elements with empty/too-short names (usually noise)
        if (name.length < minNameLength && !node.value) continue;

        // Extract value
        const value = node.value?.value;

        // Extract relevant states
        const states: string[] = [];
        if (node.properties) {
            for (const prop of node.properties) {
                if (RELEVANT_STATES.has(prop.name) && prop.value?.value === true) {
                    states.push(prop.name);
                }
            }
        }

        const element: AxElement = {
            id: nextId++,
            role,
            name: name.substring(0, 100), // Cap name length for token budget
            depth: depthMap.get(node.nodeId) ?? 0,
        };

        if (value !== undefined && value !== null && value !== "") {
            element.value = String(value).substring(0, 50);
        }

        if (states.length > 0) {
            element.state = states;
        }

        elements.push(element);

        // Enforce max elements cap
        if (elements.length >= maxElements) break;
    }

    return elements;
}

function formatAxSnapshot(
    elements: AxElement[],
    tokenBudget: number = 2000
): string {
    if (elements.length === 0) {
        return "[AxTree] Trang trống hoặc không có phần tử tương tác.";
    }

    const lines: string[] = [];
    let charCount = 0;
    const charBudget = tokenBudget * 4; // ~4 chars per token

    for (const el of elements) {
        let line = `id=${el.id} | ${el.role} | "${el.name}"`;

        if (el.value) {
            line += ` [value="${el.value}"]`;
        }

        if (el.state && el.state.length > 0) {
            line += ` [${el.state.join(", ")}]`;
        }

        // Check token budget
        if (charCount + line.length > charBudget) {
            lines.push(`... (cắt ngắn, còn ${elements.length - lines.length} phần tử nữa)`);
            break;
        }

        lines.push(line);
        charCount += line.length + 1; // +1 for newline
    }

    const header = `[AxTree Snapshot — ${elements.length} elements]`;
    return header + "\n" + lines.join("\n");
}

function getInteractiveElements(elements: AxElement[]): AxElement[] {
    return elements.filter(el => INTERACTIVE_ROLES.has(el.role));
}

function findElement(
    elements: AxElement[],
    role: string,
    namePattern: string | RegExp
): AxElement | undefined {
    return elements.find(el => {
        if (el.role !== role) return false;
        if (typeof namePattern === "string") {
            return el.name.toLowerCase().includes(namePattern.toLowerCase());
        }
        return namePattern.test(el.name);
    });
}

function getAxTreeStats(elements: AxElement[]): {
    total: number;
    interactive: number;
    semantic: number;
    estimatedTokens: number;
} {
    const interactive = elements.filter(el => INTERACTIVE_ROLES.has(el.role)).length;
    const semantic = elements.filter(el => SEMANTIC_ROLES.has(el.role)).length;
    const snapshot = formatAxSnapshot(elements);
    const estimatedTokens = Math.ceil(snapshot.length / 4);

    return { total: elements.length, interactive, semantic, estimatedTokens };
}

function isBackchannel(text: string): boolean {
    const trimmed = text.trim().toLowerCase();

    // Rule 1: Empty → backchannel
    if (!trimmed) return true;

    // Rule 2: Exact match against known fillers
    if (BACKCHANNEL_EXACT.has(trimmed)) return true;

    // Rule 3: Single filler sound pattern (ừừừm, àààà, etc.)
    if (FILLER_PATTERNS.test(trimmed)) return true;

    // Rule 4: Word count check — < 3 words AND very short
    const words = trimmed.split(/\s+/);
    if (words.length < 3 && trimmed.length < 10) {
        // Check if ALL words are fillers
        const allFiller = words.every(w => BACKCHANNEL_EXACT.has(w) || FILLER_PATTERNS.test(w));
        if (allFiller) return true;
    }

    // Default: real speech — trigger hard abort
    return false;
}

