async function waitForNavigation(
    cdp: CDPClient,
    timeoutMs = 10_000
): Promise<void> {
    return new Promise<void>((resolve, _reject) => {
        const timer = setTimeout(() => {
            cdp.off("Page.loadEventFired", handler);
            resolve(); // Don't reject — soft timeout
        }, timeoutMs);

        const handler = () => {
            clearTimeout(timer);
            cdp.off("Page.loadEventFired", handler);
            resolve();
        };
        cdp.on("Page.loadEventFired", handler);
    });
}

