async function clickByAxId(
    cdp: CDPClient,
    axId: number
): Promise<string> {
    const element = cachedAxElements.find(el => el.id === axId);
    if (!element) {
        return `[Lỗi] Không tìm thấy phần tử với id=${axId}. Hãy gọi ax_snapshot lại.`;
    }

    // Strategy: Use DOM.focus + Runtime.evaluate to find and click the element
    // We need to use JavaScript evaluation since AxTree IDs don't directly map to DOM nodes
    const clickScript = `
        (function() {
            // Find elements matching the role and name
            const role = ${JSON.stringify(element.role)};
            const name = ${JSON.stringify(element.name)};
            
            // Try aria role + accessible name matching
            const candidates = document.querySelectorAll('[role="' + role + '"], ' + role);
            for (const el of candidates) {
                const elName = el.getAttribute('aria-label') || el.textContent?.trim() || '';
                if (elName.includes(name) || name.includes(elName.substring(0, 20))) {
                    el.scrollIntoView({ block: 'center' });
                    el.click();
                    return 'clicked: ' + role + ' "' + elName.substring(0, 50) + '"';
                }
            }
            
            // Fallback: search by text content across all interactive elements
            const allInteractive = document.querySelectorAll('a, button, input, select, [role], [tabindex]');
            for (const el of allInteractive) {
                const elText = el.getAttribute('aria-label') || el.textContent?.trim() || '';
                if (elText.includes(name) || name.includes(elText.substring(0, 20))) {
                    el.scrollIntoView({ block: 'center' });
                    el.click();
                    return 'clicked (fallback): "' + elText.substring(0, 50) + '"';
                }
            }
            
            return 'not_found';
        })()
    `;

    try {
        const result = await cdp.evaluate(clickScript);

        if (result === "not_found") {
            return `[Lỗi] Không thể click phần tử id=${axId} (${element.role}: "${element.name}"). Phần tử có thể bị ẩn hoặc bị overlay che.`;
        }

        // Wait briefly for any navigation/UI update
        await new Promise(r => setTimeout(r, 500));

        return `[Đã click] ${element.role}: "${element.name}" (id=${axId})`;
    } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
        return `[Lỗi click] ${errMsg}`;
    }
}

async function typeIntoElement(
    cdp: CDPClient,
    axId: number,
    text: string
): Promise<string> {
    const element = cachedAxElements.find(el => el.id === axId);
    if (!element) {
        return `[Lỗi] Không tìm thấy phần tử với id=${axId}. Hãy gọi ax_snapshot lại.`;
    }

    // Focus the element first
    const focusScript = `
        (function() {
            const name = ${JSON.stringify(element.name)};
            const inputs = document.querySelectorAll('input, textarea, [contenteditable="true"], [role="textbox"], [role="searchbox"], [role="combobox"]');
            for (const el of inputs) {
                const elName = el.getAttribute('aria-label') || el.getAttribute('placeholder') || el.getAttribute('name') || '';
                if (elName.includes(name) || name.includes(elName.substring(0, 20))) {
                    el.scrollIntoView({ block: 'center' });
                    el.focus();
                    if (el.select) el.select();
                    return 'focused';
                }
            }
            return 'not_found';
        })()
    `;

    const focusResult = await cdp.evaluate(focusScript);
    if (focusResult === "not_found") {
        return `[Lỗi] Không thể focus vào phần tử id=${axId} (${element.role}: "${element.name}")`;
    }

    // Clear existing content and type new text
    await cdp.insertText(text);

    return `[Đã nhập] "${text.substring(0, 30)}${text.length > 30 ? "..." : ""}" vào ${element.role}: "${element.name}" (id=${axId})`;
}

async function scrollPage(
    cdp: CDPClient,
    direction: "up" | "down",
    amount = 500
): Promise<string> {
    const deltaY = direction === "up" ? -amount : amount;
    await cdp.scrollPage(deltaY);

    // Wait for any lazy-loaded content
    await new Promise(r => setTimeout(r, 300));

    return `[Đã cuộn trang ${direction === "up" ? "lên" : "xuống"}]`;
}

async function extractPageText(
    cdp: CDPClient,
    maxLength = 3000
): Promise<string> {
    const text = await cdp.evaluate(`
        (function() {
            const remove = document.querySelectorAll('script, style, nav, footer, header, aside, iframe, noscript');
            remove.forEach(el => el.remove());
            let text = document.body?.innerText || '';
            text = text.replaceAll(/\\n{3,}/g, '\\n\\n').trim();
            return text;
        })()
    `);

    const title = await cdp.getPageTitle();
    const url = await cdp.getCurrentUrl();

    let result = `[Trang: ${title}]\n[URL: ${url}]\n\n`;
    result += (text || "").substring(0, maxLength);
    if ((text || "").length > maxLength) {
        result += "\n\n... (cắt ngắn)";
    }
    return result;
}

async function pressKey(
    cdp: CDPClient,
    key: string
): Promise<string> {
    // Map common key names to CDP key identifiers
    const keyMap: Record<string, { key: string; code: string; keyCode: number }> = {
        "enter":  { key: "Enter",  code: "Enter",  keyCode: 13 },
        "tab":    { key: "Tab",    code: "Tab",    keyCode: 9 },
        "escape": { key: "Escape", code: "Escape", keyCode: 27 },
        "space":  { key: " ",      code: "Space",  keyCode: 32 },
        "backspace": { key: "Backspace", code: "Backspace", keyCode: 8 },
        "delete": { key: "Delete", code: "Delete", keyCode: 46 },
        "arrowup":    { key: "ArrowUp",    code: "ArrowUp",    keyCode: 38 },
        "arrowdown":  { key: "ArrowDown",  code: "ArrowDown",  keyCode: 40 },
        "arrowleft":  { key: "ArrowLeft",  code: "ArrowLeft",  keyCode: 37 },
        "arrowright": { key: "ArrowRight", code: "ArrowRight", keyCode: 39 },
    };

    const mapped = keyMap[key.toLowerCase()];
    if (!mapped) {
        return `[Lỗi] Phím "${key}" không được hỗ trợ. Các phím: Enter, Tab, Escape, Space, Backspace, Delete, ArrowUp/Down/Left/Right`;
    }

    await cdp.send("Input.dispatchKeyEvent", {
        type: "keyDown",
        key: mapped.key,
        code: mapped.code,
        windowsVirtualKeyCode: mapped.keyCode,
        nativeVirtualKeyCode: mapped.keyCode,
    });
    await cdp.send("Input.dispatchKeyEvent", {
        type: "keyUp",
        key: mapped.key,
        code: mapped.code,
        windowsVirtualKeyCode: mapped.keyCode,
        nativeVirtualKeyCode: mapped.keyCode,
    });

    return `[Đã nhấn phím] ${key}`;
}

async function takeScreenshot(
    cdp: CDPClient,
    savePath: string
): Promise<string> {
    const { promises: fsp } = await import("fs");
    const pathModule = await import("path");

    const dir = pathModule.dirname(savePath);
    await fsp.mkdir(dir, { recursive: true });

    const base64Data = await cdp.screenshot("png");
    const buffer = Buffer.from(base64Data, "base64");
    await fsp.writeFile(savePath, buffer);

    return `[Screenshot] Đã lưu tại: ${savePath}`;
}

async function findFreePort(): Promise<number> {
    return new Promise((resolve, reject) => {
        const server = net.createServer();
        server.listen(0, "127.0.0.1", () => {
            const address = server.address();
            if (address && typeof address === "object") {
                const port = address.port;
                server.close(() => resolve(port));
            } else {
                server.close(() => reject(new Error("Failed to get port")));
            }
        });
        server.on("error", reject);
    });
}

async function waitForChromeReady(port: number, maxWaitMs = 15_000): Promise<string> {
    const startTime = Date.now();
    const url = `http://127.0.0.1:${port}/json/version`;

    while (Date.now() - startTime < maxWaitMs) {
        try {
            const res = await safeFetch(url, {}, 3000);
            const data = await res.json();
            if (data.webSocketDebuggerUrl) {
                return data.webSocketDebuggerUrl as string;
            }
        } catch {
            // Chrome not ready yet, retry
        }
        await new Promise(r => setTimeout(r, 500));
    }

    throw new Error(`[ChromeLauncher] Chrome didn't start within ${maxWaitMs}ms on port ${port}`);
}

class ChromeLauncher {
    /**
     * Launch Chrome with CDP enabled or connect to existing instance.
     * Uses dynamic port allocation to avoid conflicts.
     * 
     * @returns WebSocket debug URL for CDPClient.connect()
     */
    static async launchOrConnect(requestedPort?: number): Promise<string> {
        // If already running with a valid connection, reuse it
        if (chromeWsUrl && chromePort > 0) {
            try {
                await safeFetch(`http://127.0.0.1:${chromePort}/json/version`, {}, 3000);
                logger.info(`[ChromeLauncher] Reusing existing Chrome on port ${chromePort}`);
                return chromeWsUrl;
            } catch {
                // Existing Chrome died, clean up and relaunch
                logger.warn("[ChromeLauncher] Existing Chrome is dead. Relaunching...");
                await this.shutdown();
            }
        }

        // Cleanup any orphaned zombies from a previous LIVA crash that might be locking the profile
        await this.cleanupZombies();

        // Allocate port
        const port = requestedPort ?? await findFreePort();
        chromePort = port;

        // Create isolated profile directory
        chromeProfileDir = path.resolve(process.cwd(), "data", "cdp_chrome_profile");
        try {
            await fs.promises.access(chromeProfileDir);
        } catch {
            await fs.promises.mkdir(chromeProfileDir, { recursive: true });
        }

        // Detect Chrome binary
        const chromePath = await detectSystemBrowser();

        // Launch Chrome
        const args = [
            `--remote-debugging-port=${port}`,
            `--user-data-dir=${chromeProfileDir}`,
            "--no-first-run",
            "--no-default-browser-check",
            "--disable-extensions",
            "--disable-blink-features=AutomationControlled",
            "--disable-background-timer-throttling",
            "--disable-backgrounding-occluded-windows",
            "--disable-renderer-backgrounding",
            // Stealth args
            "--disable-infobars",
            "--disable-dev-shm-usage",
        ];

        logger.info(`[ChromeLauncher] Launching Chrome on port ${port}...`);

        chromeProcess = spawn(chromePath, args, { // NOSONAR
            detached: true,
            stdio: "ignore",
            shell: false
        });
        chromeProcess.on('error', (err) => logger.error(err, "[ChromeLauncher] Chrome spawn error:"));
        chromeProcess.unref();

        // Handle process exit
        chromeProcess.on("exit", (code, signal) => {
            logger.warn(`[ChromeLauncher] Chrome process exited (code=${code}, signal=${signal})`);
            chromeProcess = null;
            chromeWsUrl = "";
        });

        // Wait for Chrome to be ready
        chromeWsUrl = await waitForChromeReady(port);
        logger.info(`[ChromeLauncher] ✅ Chrome ready on port ${port}`);
        logger.info(`[ChromeLauncher] Profile: ${chromeProfileDir}`);

        return chromeWsUrl;
    }

