        const ranges = ts.getLeadingCommentRanges(fullText, node.pos);
        if (ranges) {
            for (const range of ranges) {
                const comment = fullText.substring(range.pos, range.end);
                // Vắt cạn JSDoc: Giữ Summary, ném rác @param đi
                if (comment.startsWith("/**")) {
                    const cleaned = comment.split('\n').filter(l => !l.includes("* @")).join('\n');
                    fileBody += cleaned + "\n";
                }
            }
        }
    }

function visit(node: ts.Node) {
        // Dependency Trace
        if (ts.isImportDeclaration(node)) {
            const importText = node.getText(sourceFile);
            // Phép Khử Băng Kép: Chỉ giữ Import chéo nội bộ
            if (importText.includes(" from './") || importText.includes(" from '../")) {
                fileBody += importText + "\n";
            }
        } 
        else if (ts.isClassDeclaration(node) && node.name) {
            extractJSDocAndComments(node);
            let classSig = `export class ${node.name.text} {\n`;
            node.members.forEach(m => {
                extractJSDocAndComments(m);
                if (ts.isMethodDeclaration(m) || ts.isPropertyDeclaration(m)) {
                    const text = m.getText(sourceFile);
                    const bodyPos = text.indexOf('{');
                    if (bodyPos !== -1) {
                        classSig += "  " + text.substring(0, bodyPos).trim() + ";\n";
                    } else {
                        classSig += "  " + text + "\n";
                    }
                }
            });
            classSig += "}\n";
            fileBody += classSig;
        } 
        else if (ts.isFunctionDeclaration(node) && node.name) {
            extractJSDocAndComments(node);
            const text = node.getText(sourceFile);
            const bodyPos = text.indexOf('{');
            if (bodyPos !== -1) {
                fileBody += "export " + text.substring(0, bodyPos).trim() + ";\n";
            } else {
                fileBody += text + "\n";
            }
        } 
        else if (ts.isVariableStatement(node) && node.modifiers?.some(m => m.kind === ts.SyntaxKind.ExportKeyword)) {
            extractJSDocAndComments(node);
            node.declarationList.declarations.forEach(d => {
               if (ts.isVariableDeclaration(d) && d.initializer && ts.isArrowFunction(d.initializer)) {
                    const text = d.initializer.getText(sourceFile);
                    const bodyPos = text.indexOf('{');
                    const sig = bodyPos !== -1 ? text.substring(0, bodyPos).trim() : text;
                    fileBody += `export const ${d.name.getText(sourceFile)} = ${sig} /*...*/;\n`;
               } else {
                    fileBody += `export const ${d.name.getText(sourceFile)};\n`;
               }
            });
        } 
        else if (ts.isInterfaceDeclaration(node) || ts.isTypeAliasDeclaration(node)) {
            extractJSDocAndComments(node);
            fileBody += node.getText(sourceFile) + "\n";
        }

        ts.forEachChild(node, visit);
    }

async function scan(dir: string) {
    const files = await fsp.readdir(dir);
    for (const f of files) {
        const full = path.join(dir, f);
        if ((await fsp.stat(full)).isDirectory()) {
            if (f !== "node_modules" && f !== "dist") await scan(full);
        } else {
            // Lưới tàng hình (Bỏ qua file Rác/Test)
            if (f.startsWith("test_") || f.endsWith(".d.ts") || f.endsWith(".json")) continue;
            await extractSkeleton(full);
        }
    }
}

async function getGoogleAuthClient(): Promise<InstanceType<typeof google.auth.OAuth2>> {
  if (!fs.existsSync(CREDENTIALS_PATH)) {
    throw new Error(
      `[Google Auth] Không tìm thấy file credentials.json tại ${CREDENTIALS_PATH}. Vui lòng tạo trên Google Cloud Console.`,
    );
  }

  // 🔒 [Audit H-3] Async I/O — avoid blocking event loop
  const credentials = JSON.parse(await fsp.readFile(CREDENTIALS_PATH, "utf8"));

  // Nếu là file Service Account (chứa type="service_account")
  if (credentials.type === "service_account") {
    logger.info("[Google Auth] Đang sử dụng Service Account.");
    const auth = new google.auth.GoogleAuth({
      keyFile: CREDENTIALS_PATH,
      scopes: SCOPES,
    });
    return await auth.getClient() as InstanceType<typeof google.auth.OAuth2>;
  }

  // Nếu là file OAuth2 Desktop Client
  const { client_secret, client_id, redirect_uris } =
    credentials.installed || credentials.web;
  if (!client_secret || !client_id) {
    throw new Error("[Google Auth] File credentials.json không hợp lệ.");
  }

  const oAuth2Client = new google.auth.OAuth2(
    client_id,
    client_secret,
    redirect_uris[0],
  );

  // Check if we have previously stored a token.
  if (!fs.existsSync(TOKEN_PATH)) {
    throw new Error(
      `[Google Auth] Chưa được cấp quyền OAuth2 (Không tìm thấy token.json). Vui lòng chạy lệnh: npx tsx src/utils/auth_google_script.ts để đăng nhập lần đầu.`,
    );
  }

  // 🔒 [Audit H-3] Async I/O
  const token = JSON.parse(await fsp.readFile(TOKEN_PATH, "utf8"));
  oAuth2Client.setCredentials(token);

  // Auto-refresh token if needed
  oAuth2Client.on("tokens", (tokens) => {
    if (tokens.refresh_token) {
      // Modify token locally and save
      token.refresh_token = tokens.refresh_token;
    }
    token.access_token = tokens.access_token;
    // 🔒 [Audit H-3] Atomic Write: .tmp + rename to prevent token corruption
    const tmpPath = `${TOKEN_PATH}.tmp`;
    fsp.writeFile(tmpPath, JSON.stringify(token), "utf-8")
      .then(() => safeRename(tmpPath, TOKEN_PATH))
      .catch(e => logger.error(e, "[Google Auth] Atomic token save failed"));
    logger.info("[Google Auth] Đã làm mới token thành công.");
  });

  return oAuth2Client;
}

class HeuristicSemanticChunker {
    /**
     * Splits a text into semantic chunks.
     * Heuristic-first: cuts text into sentences/paragraphs first.
     * Only calls EmbeddingService when chunk size exceeds softLimit (150 tokens).
     * Hard limits at hardLimit (256 tokens) to prevent ONNX sequence truncation.
     */
    public static async chunk(
        text: string, 
        embeddingService: EmbeddingService, 
        softLimit: number = 150, 
        hardLimit: number = 256
    ): Promise<string[]> {
        if (!text || text.trim().length === 0) return [];

        // 1. Cut into sentences/paragraphs using regex
        const rawSentences = text.split(/(?<=[.?!])\s+|\n+/);
        const sentences = rawSentences.map(s => s.trim()).filter(s => s.length > 0);

        if (sentences.length === 0) return [];

        const chunks: string[] = [];
        let currentChunkSentences: string[] = [];
        let currentChunkTokens = 0;

        const getApproxTokens = (t: string) => {
            const words = t.trim().split(/\s+/).filter(w => w.length > 0).length;
            return Math.ceil(words * 1.3);
        };

        for (const sentence of sentences) {
            const sentenceTokens = getApproxTokens(sentence);

            // If appending the sentence exceeds the hardLimit, we must finalize the current chunk first
            if (currentChunkSentences.length > 0 && currentChunkTokens + sentenceTokens > hardLimit) {
                chunks.push(currentChunkSentences.join(" "));
                currentChunkSentences = [sentence];
                currentChunkTokens = sentenceTokens;
                continue;
            }

            // If we are below the softLimit, we simply append (Heuristic-First)
            if (currentChunkTokens < softLimit) {
                currentChunkSentences.push(sentence);
                currentChunkTokens += sentenceTokens;
                continue;
            }

            // If we are between softLimit and hardLimit, we check for semantic Topic Shift
            try {
                const currentChunkText = currentChunkSentences.join(" ");
                const [vec1, vec2] = await Promise.all([
                    embeddingService.embed(currentChunkText),
                    embeddingService.embed(sentence)
                ]);

                const similarity = cosineSimilarity(vec1, vec2);
                if (similarity < 0.65) {
                    // Topic shift detected -> split!
                    logger.debug(`[HeuristicSemanticChunker] Topic shift detected (similarity=${similarity.toFixed(3)}). Splitting chunk.`);
                    chunks.push(currentChunkText);
                    currentChunkSentences = [sentence];
                    currentChunkTokens = sentenceTokens;
                } else {
                    // Same topic -> append
                    currentChunkSentences.push(sentence);
                    currentChunkTokens += sentenceTokens;
                }
            } catch (err: unknown) {
                // Fail-safe: if embedding fails, fall back to simple greedy append
                const msg = err instanceof Error ? err.message : String(err);
                logger.warn(`[HeuristicSemanticChunker] Embedding failed, falling back to greedy append: ${msg}`);
                currentChunkSentences.push(sentence);
                currentChunkTokens += sentenceTokens;
            }
        }

        // Add the remaining sentences if any
        if (currentChunkSentences.length > 0) {
            chunks.push(currentChunkSentences.join(" "));
        }

        return chunks;
    }
}

