function getSystemChromePath(): string {
    if (cachedBrowserPath) return cachedBrowserPath;

    const candidates = [
        // Chrome
        process.env.CHROME_PATH,
        "C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe",
        "C:\\Program Files (x86)\\Google\\Chrome\\Application\\chrome.exe",
        path.join(process.env.LOCALAPPDATA || "", "Google", "Chrome", "Application", "chrome.exe"),
        // Edge
        "C:\\Program Files (x86)\\Microsoft\\Edge\\Application\\msedge.exe",
        "C:\\Program Files\\Microsoft\\Edge\\Application\\msedge.exe",
        // Linux/macOS fallbacks
        "/usr/bin/google-chrome",
        "/usr/bin/chromium-browser",
        "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
    ];

    for (const candidate of candidates) {
        if (candidate && fs.existsSync(candidate)) {
            cachedBrowserPath = candidate;
            logger.info(`[PlaywrightBrowser] Detected system browser: ${candidate}`);
            return candidate;
        }
    }

    throw new Error(
        "[PlaywrightBrowser] Không tìm thấy Chrome hoặc Edge trên máy. " +
        "Hãy cài Chrome tại: https://www.google.com/chrome/ hoặc set CHROME_PATH env var."
    );
}

async function getOrCreateBrowser(profileName: string, headless: boolean = true): Promise<{ browser: Browser; context: BrowserContext }> {
    const slotKey = `${profileName}_${headless ? 'headless' : 'headful'}`;
    const existing = browserSlots.get(slotKey);
    if (existing) {
        return { browser: existing.browser, context: existing.context };
    }

    // Nếu profile này đang mở ở chế độ khác (ví dụ đang headless mà muốn mở headful), đóng cái cũ đi
    const altSlotKey = `${profileName}_${!headless ? 'headless' : 'headful'}`;
    const altExisting = browserSlots.get(altSlotKey);
    if (altExisting) {
        logger.info(`[PlaywrightBrowser] Đóng browser profile "${profileName}" cũ để đổi chế độ headless=${headless}`);
        await altExisting.context.close().catch(() => {});
        browserSlots.delete(altSlotKey);
    }

    const profileDir = path.resolve(process.cwd(), "data", `liva_${profileName}_profile`);
    if (!fs.existsSync(profileDir)) {
        fs.mkdirSync(profileDir, { recursive: true });
    }

    logger.info(`[PlaywrightBrowser] Launching browser for profile: ${profileName} (headless: ${headless})`);

    const browser = await chromium.launchPersistentContext(profileDir, {
        executablePath: getSystemChromePath(),
        headless: headless,
        viewport: null,
        args: [
            "--start-maximized",
            "--disable-extensions",
            "--disable-blink-features=AutomationControlled",
        ],
        ignoreDefaultArgs: ["--enable-automation"],
        // Stealth: override navigator.webdriver
        bypassCSP: true,
    });

    // Clean up from cache when closed
    browser.on("close", () => {
        logger.info(`[PlaywrightBrowser] Browser context for profile "${profileName}" closed.`);
        browserSlots.delete(slotKey);
    });

    // Anti-bot: inject stealth script on every new page
    browser.on("page", async (page) => {
        await page.addInitScript(() => {
            Object.defineProperty(navigator, "webdriver", { get: () => undefined });
        });
    });

    // Set realistic user agent
    const pages = browser.pages();
    for (const page of pages) {
        await page.addInitScript(() => {
            Object.defineProperty(navigator, "webdriver", { get: () => undefined });
        });
    }

    browserSlots.set(slotKey, {
        browser: browser as unknown as Browser,
        context: browser,
        profileDir,
    });

    return { browser: browser as unknown as Browser, context: browser };
}

async function getActivePage(context: BrowserContext, urlFilter?: string): Promise<Page> {
    const pages = context.pages();

    if (urlFilter) {
        const match = pages.find(p => p.url().includes(urlFilter));
        if (match) return match;
    }

    return pages[pages.length - 1] || await context.newPage();
}

async function closeBrowser(profileName: string): Promise<void> {
    const slot = browserSlots.get(profileName);
    if (slot) {
        await slot.context.close().catch(() => {});
        browserSlots.delete(profileName);
    }
}

class ShieldGuard {
    private static async existsAsync(p: string): Promise<boolean> {
        try {
            await fsp.access(p);
            return true;
        } catch {
            return false;
        }
    }

    public static async deploy() {
        try {
            if (!(await this.existsAsync(SHIELD_DIR))) {
                await fsp.mkdir(SHIELD_DIR);
            }
            
            // Xóa hầm an toàn cũ
            if (await this.existsAsync(SNAPSHOT_DIR)) {
                await fsp.rm(SNAPSHOT_DIR, { recursive: true, force: true });
            }
            await fsp.mkdir(SNAPSHOT_DIR);

            // Copy src
            logger.info("🛡️ [ShieldGuard] Đang sao lưu Code lõi (src/) sang Vùng An Toàn...");
            await fsp.cp(path.join(process.cwd(), "src"), path.join(SNAPSHOT_DIR, "src"), { recursive: true });

            // Copy data
            logger.info("🛡️ [ShieldGuard] Đang sao lưu Trí nhớ (data/) sang Vùng An Toàn...");
            if (await this.existsAsync(path.join(process.cwd(), "data"))) {
                await fsp.cp(path.join(process.cwd(), "data"), path.join(SNAPSHOT_DIR, "data"), { recursive: true });
            }

            logger.info("✅ [ShieldGuard] Hệ thống phòng ngự đã kích hoạt! Đã Snapshot thành công.");
        } catch (e: unknown) {
            const errMsg = e instanceof Error ? e.message : String(e);
            logger.error("⛔ [ShieldGuard] Lỗi kích hoạt khiên: " + errMsg);
        }
    }

    public static async rollback() {
        logger.warn("⚠️ [ShieldGuard] KHỞI CHẠY QUY TRÌNH PHỤC HỒI KÍ TỰ...");
        if (!(await this.existsAsync(SNAPSHOT_DIR))) {
            logger.error("⛔ [ShieldGuard] Không tìm thấy bản Snapshot nào!");
            return;
        }

        try {
            // Khôi phục src
            await fsp.cp(path.join(SNAPSHOT_DIR, "src"), path.join(process.cwd(), "src"), { recursive: true, force: true });
            
            // Khôi phục data
            const dataBackupPath = path.join(SNAPSHOT_DIR, "data");
            if (await this.existsAsync(dataBackupPath)) {
                await fsp.cp(dataBackupPath, path.join(process.cwd(), "data"), { recursive: true, force: true });
            }
            
            logger.info("🎯 [ShieldGuard] Phục hồi THÀNH CÔNG! Mã nguồn đã quay về trạng thái ổn định gần nhất.");
        } catch (e: unknown) {
            const errMsg = e instanceof Error ? e.message : String(e);
            logger.error("⛔ [ShieldGuard] Lỗi phục hồi: " + errMsg);
        }
    }
}

