        }

        // Priority 4: Word count overflow — force split at last space
        const wordCount = this.#buffer.trim().split(/\s+/).length;
        if (wordCount >= MAX_WORDS_BEFORE_FORCE_SPLIT && this.#buffer.length > MIN_CLAUSE_LENGTH) {
            const lastSpace = this.#buffer.lastIndexOf(' ');
            if (lastSpace > MIN_CLAUSE_LENGTH) {
                const chunk = this.#buffer.substring(0, lastSpace).trim();
                this.#buffer = this.#buffer.substring(lastSpace + 1);

                const sanitized = this.#sanitize(chunk);
                return (sanitized.length > 0 && this.#hasSpeakableContent(sanitized)) ? sanitized : null;
            }
        }

        return null;
    }

flush(): string | null {
        if (!this.#buffer.trim()) {
            this.#buffer = "";
            return null;
        }

        const sanitized = this.#sanitize(this.#buffer.trim());
        this.#buffer = "";
        return (sanitized.length > 0 && this.#hasSpeakableContent(sanitized)) ? sanitized : null;
    }

reset(): void {
        this.#buffer = "";
    }

#sanitize(text: string): string {
        let result = text;

        // 1. Remove fenced code blocks first (```...```)
        result = result.replace(CODE_BLOCK_PATTERN, "");

        // 2. Remove inline code (`...`)
        result = result.replace(INLINE_CODE_PATTERN, "");

        // 3. Remove URLs
        result = result.replace(URL_PATTERN, "");

        // 4. Extract text from Markdown links [text](url) → text
        result = result.replace(MARKDOWN_LINK, "$1");

        // 5. Strip Markdown formatting (preserve inner text)
        result = result.replace(MARKDOWN_BOLD_ITALIC, "$1");
        result = result.replace(MARKDOWN_UNDERLINE, "$1");
        result = result.replace(MARKDOWN_STRIKE, "$1");
        result = result.replace(MARKDOWN_HEADER, "");
        result = result.replace(MARKDOWN_BLOCKQUOTE, "");
        result = result.replace(MARKDOWN_LIST, "");
        result = result.replace(MARKDOWN_ORDERED_LIST, "");

        // 6. Replace angle brackets with spaces (XML/HTML tag leaks)
        result = result.replace(ANGLE_BRACKETS, " ");

        // 7. Remove all emoji
        result = result.replace(EMOJI_PATTERN, "");

        // 8. Collapse multiple whitespace into single space
        result = result.replace(MULTI_WHITESPACE, " ");

        return result.trim();
    }

function encodeTime(timestamp: number, length: number): string {
    let result = "";
    for (let i = length - 1; i >= 0; i--) {
        result = CROCKFORD_BASE32[timestamp & 31]! + result;
        timestamp = Math.floor(timestamp / 32);
    }
    return result;
}

function encodeRandom(length: number): string {
    const bytes = crypto.randomBytes(length);
    let result = "";
    for (let i = 0; i < length; i++) {
        result += CROCKFORD_BASE32[bytes[i]! & 31];
    }
    return result;
}

function generateULID(): string {
    return encodeTime(Date.now(), 10) + encodeRandom(16);
}

function cosineSimilarityF32(a: Float32Array, b: Float32Array): number {
    if (a.length !== b.length || a.length === 0) return 0;

    const len = a.length;
    const rem = len % 4;
    let dot = 0, normA = 0, normB = 0;

    // 4-wide unrolled main loop
    for (let i = 0; i < len - rem; i += 4) {
        dot   += a[i]*b[i] + a[i+1]*b[i+1] + a[i+2]*b[i+2] + a[i+3]*b[i+3];
        normA += a[i]*a[i] + a[i+1]*a[i+1] + a[i+2]*a[i+2] + a[i+3]*a[i+3];
        normB += b[i]*b[i] + b[i+1]*b[i+1] + b[i+2]*b[i+2] + b[i+3]*b[i+3];
    }

    // Remainder tail loop
    for (let i = len - rem; i < len; i++) {
        dot += a[i] * b[i];
        normA += a[i] * a[i];
        normB += b[i] * b[i];
    }

    if (normA === 0 || normB === 0) return 0;
    return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

function cosineSimilarity(a: number[], b: number[]): number {
    if (a.length !== b.length || a.length === 0) return 0;

    const len = a.length;
    const rem = len % 4;
    let dot = 0, normA = 0, normB = 0;

    // 4-wide unrolled main loop
    for (let i = 0; i < len - rem; i += 4) {
        dot   += a[i]*b[i] + a[i+1]*b[i+1] + a[i+2]*b[i+2] + a[i+3]*b[i+3];
        normA += a[i]*a[i] + a[i+1]*a[i+1] + a[i+2]*a[i+2] + a[i+3]*a[i+3];
        normB += b[i]*b[i] + b[i+1]*b[i+1] + b[i+2]*b[i+2] + b[i+3]*b[i+3];
    }

    // Remainder tail loop
    for (let i = len - rem; i < len; i++) {
        dot += a[i] * b[i];
        normA += a[i] * a[i];
        normB += b[i] * b[i];
    }

    if (normA === 0 || normB === 0) return 0;
    return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

async function notifyZalo(msg: string, targetUserId?: string) {
  const token = process.env.ZALO_OA_ACCESS_TOKEN;
  const userId = targetUserId || process.env.ZALO_USER_ID;
  if (!token || !userId) return;

  // [AUTO-TAG] Append #Liva signature so recipients know this is AI-generated
  const taggedMsg = msg.includes("#Liva") ? msg : `${msg}\n\n#Liva`;

  try {
     const isBotToken = token.includes(":");
     const endpoint = isBotToken 
         ? `https://bot-api.zaloplatforms.com/bot${token}/sendMessage`
         : "https://openapi.zalo.me/v3.0/oa/message/cs";
     
     if (isBotToken) {
         await safeFetch(endpoint, {
             method: "POST",
             headers: { "Content-Type": "application/json" },
             body: JSON.stringify({ chat_id: userId, text: taggedMsg })
         });
     } else {
         await safeFetch(endpoint, {
             method: "POST",
             headers: { 
                 access_token: token,
                 "Content-Type": "application/json" 
             },
             body: JSON.stringify({
                recipient: { user_id: userId },
                message: { text: taggedMsg }
             })
         });
     }
  } catch(e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e);
      logger.error(`[ZaloNotifier] Nhắn Zalo thất bại: ${errMsg}`);
  }
}

function getSchemaName(schema: ZodSchema<unknown>): string {
    return schema.description || "Unknown";
}

function safeParse<T>(
    schema: ZodSchema<T>,
    data: unknown,
    fallbackData: T,
    context?: string
): SafeParseResult<T> {
    const result = schema.safeParse(data);
    
    if (result.success) {
        return { success: true, data: result.data };
    }
    
    // Shadow mode: log warning but return fallback data
    const schemaName = getSchemaName(schema);
    logger.warn({
        context: "ZodSafeParse",
        schemaName,
        error: result.error.message,
        path: result.error.issues.map(i => i.path.join(".")).join(", "),
    }, `Type mismatch detected${context ? ` in ${context}` : ""}, using fallback`);
    
    return { success: false, data: fallbackData, error: result.error };
}

function tryParseOrDefault<T>(
    schema: ZodSchema<T>,
    data: unknown,
    defaultValue: T,
    context?: string
): T {
    const result = safeParse(schema, data, defaultValue, context);
    return result.data as T;
}

function assertParse<T>(schema: ZodSchema<T>, data: unknown, context?: string): T {
    const result = schema.safeParse(data);
    if (!result.success) {
        const schemaName = getSchemaName(schema);
        const error = new Error(
            `Zod assertion failed${context ? ` in ${context}` : ""}: ${result.error.message}`
        );
        logger.error({
            context: "ZodAssert",
            schemaName,
            error: result.error.message,
            issues: result.error.issues,
        }, error.message);
        throw error;
    }
    return result.data;
}

function buildStringSchema(maxLength: number, description?: string) {
    return z.string().max(maxLength, `Max ${maxLength} chars`).describe(description || "String");
}

function optionalWithDefault<T>(
    schema: ZodSchema<T>,
    defaultValue: NoInfer<T>
): ZodSchema<T> {
    return schema.optional().default(defaultValue as never) as unknown as ZodSchema<T>;
}

function buildUnionSchema<
    T extends Record<string, ZodSchema>
>(
    _discriminant: keyof T,
    schemas: T
): ZodSchema {
    const values = Object.values(schemas);
    if (values.length < 2) {
        return values[0] ?? z.never();
    }
    return z.union(
        [values[0], values[1], ...values.slice(2)] as [ZodSchema, ZodSchema, ...ZodSchema[]]
    );
}

function buildObjectSchema<T extends z.ZodRawShape>(
    shape: T,
    description?: string
): z.ZodObject<T> {
    const schema = z.object(shape);
    return description ? schema.describe(description) : schema;
}

function initialize(dbPath: string, options?: { allowExtension?: boolean }): void {
    try {
        // Ensure parent directory exists
        if (dbPath !== ":memory:") {
            const dir = path.dirname(dbPath);
            if (!fs.existsSync(dir)) {
                fs.mkdirSync(dir, { recursive: true });
            }
        }

        const backupPath = `${dbPath}.bak`;

        const openAndCheck = (targetPath: string): DatabaseSync => {
            const tempDb = new DatabaseSync(targetPath, {
                allowExtension: options?.allowExtension ?? true,
            });
            // Load sqlite-vec extension
            sqliteVec.load(tempDb);
            
            // integrity check
            const check = tempDb.prepare("PRAGMA integrity_check").get() as { integrity_check: string } | undefined;
            if (!check || check.integrity_check !== 'ok') {
                tempDb.close();
                throw new Error(`Integrity check failed: ${JSON.stringify(check)}`);
            }
            return tempDb;
        };

        try {
            db = openAndCheck(dbPath);
        } catch (err: unknown) {
            const errMsg = err instanceof Error ? err.message : String(err);
            
            // If primary is corrupt or fails to open, attempt backup restore
            if (dbPath !== ":memory:" && fs.existsSync(backupPath)) {
                try {
                    // Copy backup to primary (overwrite)
                    fs.copyFileSync(backupPath, dbPath);
                    
                    // Also delete wal/shm if they exist to prevent WAL synchronization conflicts
                    const shmPath = `${dbPath}-shm`;
                    const walPath = `${dbPath}-wal`;
                    if (fs.existsSync(shmPath)) {
                        try { fs.unlinkSync(shmPath); } catch {}
                    }
                    if (fs.existsSync(walPath)) {
                        try { fs.unlinkSync(walPath); } catch {}
                    }

                    // Re-open restored database
                    db = openAndCheck(dbPath);
                } catch (restoreErr: unknown) {
                    const restoreMsg = restoreErr instanceof Error ? restoreErr.message : String(restoreErr);
                    throw new Error(`Primary corrupt (${errMsg}) and backup restore failed: ${restoreMsg}`);
                }
            } else {
                throw new Error(`Primary corrupt (${errMsg}) and no backup file found.`);
            }
        }

        // Enterprise SQLite Performance Tuning
        db.exec("PRAGMA journal_mode = WAL");
        db.exec("PRAGMA synchronous = NORMAL");
        db.exec("PRAGMA busy_timeout = 5000");
        db.exec("PRAGMA wal_autocheckpoint = 1000");
        db.exec("PRAGMA cache_size = -8192");
        db.exec("PRAGMA page_size = 32768");
        db.exec("PRAGMA mmap_size = 268435456"); // 256MB mmap

        parentPort?.postMessage({ type: "ready" });
    } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        parentPort?.postMessage({ type: "error", message: `Database init failed: ${msg}` });
    }
}

function handleMessage(msg: {
    id?: string;
    type: "init" | "exec" | "run" | "runBatch" | "transactionBatch" | "all" | "get" | "backup" | "close" | "ping";
    dbPath?: string;
    options?: { allowExtension?: boolean };
    sql?: string;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    params?: any[];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    paramSets?: any[][];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    statements?: Array<{ sql: string; paramSets: any[][] }>;
    backupPath?: string;
    traceId?: string;
}): void {
    const { id, type, traceId } = msg;

    if (type === "init") {
        initialize(msg.dbPath!, msg.options);
        return;
    }

    if (type === "ping") {
        parentPort?.postMessage({ type: "pong" });
        return;
    }

    if (type === "close") {
        try {
            if (db) {
                db.close();
                db = null;
            }
            if (id) {
                parentPort?.postMessage({ id, type: "result", data: null });
            } else {
                parentPort?.postMessage({ type: "closed" });
            }
            setTimeout(() => process.exit(0), 10);
        } catch (err: unknown) {
            console.error("[DatabaseWorker] Close failed:", err);
            if (id) {
                parentPort?.postMessage({ id, type: "error", message: String(err) });
            }
            process.exit(1);
        }
        return;
    }

    const activeDb = db;
    if (!activeDb) {
        if (id) {
            parentPort?.postMessage({
                id,
                type: "error",
                message: "Database not initialized",
            });
        }
        return;
    }

    TraceContext.run(() => {
        try {
            switch (type) {
                case "exec": {
                    activeDb.exec(msg.sql!);
                    parentPort?.postMessage({ id, type: "result", data: null });
                    break;
                }
                case "run": {
                    const stmt = activeDb.prepare(msg.sql!);
                    const res = stmt.run(...(msg.params || []));
                    parentPort?.postMessage({
                        id,
                        type: "result",
                        data: {
                            changes: res.changes,
                            lastInsertRowid: res.lastInsertRowid ? Number(res.lastInsertRowid) : null,
                        },
                    });
                    break;
                }
                case "runBatch": {
                    const stmt = activeDb.prepare(msg.sql!);
                    activeDb.exec("BEGIN");
                    try {
                        let totalChanges = 0;
                        for (const p of msg.paramSets || []) {
                            const res = stmt.run(...p);
                            // Type cast to prevent bigint inference errors
                            totalChanges += Number(res.changes);
                        }
                        activeDb.exec("COMMIT");
                        parentPort?.postMessage({
                            id,
                            type: "result",
                            data: { changes: totalChanges, lastInsertRowid: null },
                        });
                    } catch (e) {
                        try { activeDb.exec("ROLLBACK"); } catch { /* ignore */ }
                        throw e;
                    }
                    break;
                }
                case "transactionBatch": {
                    activeDb.exec("BEGIN");
                    try {
                        for (const stmtDef of msg.statements || []) {
                            const stmt = activeDb.prepare(stmtDef.sql);
                            for (const p of stmtDef.paramSets) {
                                stmt.run(...p);
                            }
                        }
                        activeDb.exec("COMMIT");
                        parentPort?.postMessage({ id, type: "result", data: null });
                    } catch (e) {
                        try { activeDb.exec("ROLLBACK"); } catch { /* ignore */ }
                        throw e;
                    }
                    break;
                }
                case "all": {
                    const stmt = activeDb.prepare(msg.sql!);
                    const res = stmt.all(...(msg.params || []));
                    parentPort?.postMessage({ id, type: "result", data: res });
                    break;
                }
                case "get": {
                    const stmt = activeDb.prepare(msg.sql!);
                    const res = stmt.get(...(msg.params || []));
                    parentPort?.postMessage({ id, type: "result", data: res });
                    break;
                }
                case "backup": {
                    const bPath = msg.backupPath!;
                    // Ensure backup folder exists
                    const dir = path.dirname(bPath);
                    if (!fs.existsSync(dir)) {
                        fs.mkdirSync(dir, { recursive: true });
                    }

                    // Delete old backup if exists to prevent SQLite error
                    if (fs.existsSync(bPath)) {
                        fs.unlinkSync(bPath);
                    }

                    // Atomic Snapshot via VACUUM INTO
                    const stmt = activeDb.prepare("VACUUM INTO ?");
                    stmt.run(bPath);

                    parentPort?.postMessage({ id, type: "result", data: { backupPath: bPath } });
                    break;
                }
                default:
                    throw new Error(`Unsupported message type: ${type}`);
            }
        } catch (err: unknown) {
            const message = err instanceof Error ? err.message : String(err);
            logger.error(`[DatabaseWorker] Query failed: ${message}. SQL: ${msg.sql || "N/A"}`);
            parentPort?.postMessage({ id, type: "error", message });
        }
    }, traceId);
}

function resolveModelPath(): string {
    const cwdPath = path.join(process.cwd(), "models", "all-MiniLM-L6-v2.onnx");
    if (fs.existsSync(cwdPath)) return cwdPath;

    // Check HuggingFace cache folder
    const cachePath = path.join(
        process.cwd(),
        "node_modules",
        "@huggingface",
        "transformers",
        ".cache",
        "Xenova",
        "all-MiniLM-L6-v2",
        "onnx",
        "model.onnx"
    );
    if (fs.existsSync(cachePath)) return cachePath;

    // Direct check in nested node_modules or parent directories
    const altCachePath = path.join(
        process.cwd(),
        "..",
        "node_modules",
        "@huggingface",
        "transformers",
        ".cache",
        "Xenova",
        "all-MiniLM-L6-v2",
        "onnx",
        "model.onnx"
    );
    if (fs.existsSync(altCachePath)) return altCachePath;

    throw new Error("Could not locate all-MiniLM-L6-v2.onnx model file.");
}

async function loadModel(useGpuValue: boolean) {
    if (session) {
        try {
            await session.release();
        } catch {
            // Ignore release errors
        }
        session = null;
    }
    useGpu = useGpuValue;
    const modelPath = resolveModelPath();
    const providers = useGpu ? ["cuda", "directml", "cpu"] : ["cpu"];
    
    try {
        session = await ort.InferenceSession.create(modelPath, {
            executionProviders: providers
        });
    } catch (e: any) {
        if (useGpu) {
            // Fallback to CPU
            session = await ort.InferenceSession.create(modelPath, {
                executionProviders: ["cpu"]
            });
            useGpu = false;
        } else {
            throw e;
        }
    }
}

async function computeEmbedding(text: string): Promise<number[]> {
    if (!tokenizer || !session) {
        throw new Error("Model or tokenizer not initialized.");
    }
    const tokens = await tokenizer(text);
    
    const feeds = {
        input_ids: new ort.Tensor("int64", BigInt64Array.from(tokens.input_ids.data.map(BigInt)), tokens.input_ids.dims),
        attention_mask: new ort.Tensor("int64", BigInt64Array.from(tokens.attention_mask.data.map(BigInt)), tokens.attention_mask.dims),
        token_type_ids: new ort.Tensor("int64", new BigInt64Array(tokens.input_ids.data.length).fill(0n), tokens.input_ids.dims)
    };
    
    const outputs = await session.run(feeds);
    const lastHiddenState = outputs.last_hidden_state;
    
    const [batchSize, seqLength, dim] = lastHiddenState.dims;
    const data = lastHiddenState.data as Float32Array;
    const mask = tokens.attention_mask.data;
    
    const pooled = new Float32Array(dim);
    let validTokensCount = 0;
    
    for (let s = 0; s < seqLength; s++) {
        if (Number(mask[s]) === 1) {
            validTokensCount++;
            for (let d = 0; d < dim; d++) {
                pooled[d] += data[s * dim + d];
            }
        }
    }
    
    if (validTokensCount > 0) {
        for (let d = 0; d < dim; d++) {
            pooled[d] /= validTokensCount;
        }
    }
    
    // L2 Normalize
    let norm = 0;
    for (let d = 0; d < dim; d++) {
        norm += pooled[d] * pooled[d];
    }
    norm = Math.sqrt(norm);
    
    const normalized = new Array(dim);
    for (let d = 0; d < dim; d++) {
        normalized[d] = norm > 0 ? pooled[d] / norm : 0;
    }
    
    return normalized;
}

async function processEmbedBatch(id: string, texts: string[]) {
    try {
        const vectors = [];
        for (const text of texts) {
            vectors.push(await computeEmbedding(text));
        }
        parentPort?.postMessage({
            type: "embed_batch_result",
            id,
            vectors
        });
    } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        parentPort?.postMessage({ type: "error", id, message: `Embed batch error: ${msg}` });
    }
}

async function initialize(modelPath: string): Promise<void> {
    try {
        ort = await import("onnxruntime-web");
        ort.env.wasm.numThreads = 1;

        session = await ort.InferenceSession.create(modelPath, {
            executionProviders: ["wasm"],
        });

        // Initialize hidden state tensors (Silero VAD is stateful LSTM)
        h = new ort.Tensor("float32", new Float32Array(2 * 64).fill(0), [2, 1, 64]);
        c = new ort.Tensor("float32", new Float32Array(2 * 64).fill(0), [2, 1, 64]);

        parentPort?.postMessage({ type: "ready" });
    } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        parentPort?.postMessage({ type: "error", message: `VAD init failed: ${msg}` });
    }
}

async function processAudio(samples: Float32Array): Promise<void> {
    if (!session || !ort || !h || !c) return;

    try {
        const inputTensor = new ort.Tensor("float32", samples, [1, samples.length]);
        const srTensor = new ort.Tensor("int64", SR_TENSOR_DATA, []);

        const results = await session.run({
            input: inputTensor,
            sr: srTensor,
            h: h,
            c: c,
        });

        // Update LSTM hidden states for next frame
        h = results.hn;
        c = results.cn;

        const confidence = (results.output.data as Float32Array)[0];

        parentPort?.postMessage({
            type: "vad_result",
            isSpeech: confidence > 0.5,
            confidence,
        });
    } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        parentPort?.postMessage({ type: "error", message: `VAD inference error: ${msg}` });
    }
}
